#include&lt;iostream&gt;#include&lt;cstdio&gt;#include&lt;algorithm&gt;#include&lt;cstring&gt;#include&lt;cctype&gt;#include&lt;cstdlib&gt;const int maxn=10;using namespace std;int read()&#123;    int X=0,w=0; char ch=0;    while(!isdigit(ch)) 	&#123;		w|=ch==&#x27;-&#x27;;ch=getchar();	&#125;    while(isdigit(ch))	X=(X&lt;&lt;3)+(X&lt;&lt;1)+(ch^48),ch=getchar();    return w?-X:X;&#125;int n,map[maxn][maxn],ans[maxn][5],last[maxn][maxn][maxn],xiao[maxn][maxn];bool remove()&#123;    int flag=0;    for(int i=1;i&lt;=5;i++)        for(int j=1;j&lt;=7;j++)		&#123;            if(i-1&gt;=1&amp;&amp;i+1&lt;=5&amp;&amp;map[i][j]==map[i-1][j]&amp;&amp;map[i][j]==map[i+1][j]&amp;&amp;map[i][j])			&#123;                xiao[i-1][j]=1;				xiao[i+1][j]=1;				xiao[i][j]=1;				flag=1;            &#125;            if(j-1&gt;=1&amp;&amp;j+1&lt;=7&amp;&amp;map[i][j]==map[i][j+1]&amp;&amp;map[i][j]==map[i][j-1]&amp;&amp;map[i][j])			&#123;                xiao[i][j]=1;				xiao[i][j+1]=1;				xiao[i][j-1]=1;				flag=1;            &#125;        &#125;    if(!flag)	return 0;    for(int i=1;i&lt;=5;i++)        for(int j=1;j&lt;=7;j++)        if(xiao[i][j])		&#123;            xiao[i][j]=0;            map[i][j]=0;        &#125;     return 1;&#125;bool check()&#123;    for(int i=1;i&lt;=5;i++)        if(map[i][1])		return 0;    return 1;&#125;void copy(int x)&#123;    for(int i=1;i&lt;=5;i++)        for(int j=1;j&lt;=7;j++)        last[x][i][j]=map[i][j];&#125;void update()&#123;    for(int i=1;i&lt;=5;i++)	&#123;        int wow=0;        for(int j=1;j&lt;=7;j++)		&#123;            if(!map[i][j])			wow++;            else			&#123;                if(!wow)				continue;                map[i][j-wow]=map[i][j];                map[i][j]=0;            &#125;        &#125;    &#125;&#125;void move(int i,int j,int x)&#123;    int tmp=map[i][j];    map[i][j]=map[i+x][j];    map[i+x][j]=tmp;    update();    while(remove())	update();&#125;void dfs(int x)&#123;    if(check())	&#123;        for(int i=1;i&lt;=n;i++)		&#123;            if(i!=1)printf(&quot;\n&quot;);            for(int j=1;j&lt;=3;j++)            printf(&quot;%d &quot;,ans[i][j]);        &#125;        exit(0);    &#125;    if(x==n+1)	return;    copy(x);    for(int i=1;i&lt;=5;i++)        for(int j=1;j&lt;=7;j++)		&#123;            if(map[i][j])			&#123;                if(i+1&lt;=5&amp;&amp;map[i][j]!=map[i+1][j])				&#123;               		move(i,j,1);              		ans[x][1]=i-1;					ans[x][2]=j-1;					ans[x][3]=1;                	dfs(x+1);                	for(int i=1;i&lt;=5;i++)                    	for(int j=1;j&lt;=7;j++)                    	map[i][j]=last[x][i][j];                	ans[x][1]=-1;					ans[x][2]=-1;					ans[x][3]=-1;            &#125;            	if(i-1&gt;=1&amp;&amp;map[i-1][j]==0)				&#123;             		move(i,j,-1);         	 	    ans[x][1]=i-1;				    ans[x][2]=j-1;					ans[x][3]=-1;       		        dfs(x+1);                	for(int i=1;i&lt;=5;i++)                    	for(int j=1;j&lt;=7;j++)                   		map[i][j]=last[x][i][j];                	ans[x][1]=-1;					ans[x][2]=-1;					ans[x][3]=-1;           		&#125;        	&#125;        &#125;&#125;int main()&#123;    n=read();    for(int i=1;i&lt;=5;i++)	&#123;        for(int j=1;j&lt;=8;j++)		&#123;            int x=read();            if(x==0)			break;            map[i][j]=x;        &#125;    &#125;    memset(ans,-1,sizeof(ans));    dfs(1);    puts(&quot;-1&quot;);    return 0;&#125;
