#include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;using namespace std;const int maxn=50;int n;int h[maxn];int up[maxn],down[maxn];bool dfs(int u,int su,int sd,int depth)&#123;	if(su+sd&gt;depth)	return false;	if(u==n)//到达就好 	return true;	bool flag=true;	for(int i=1;i&lt;=su;i++)	&#123;		if(up[i]&lt;h[u])		&#123;			int t=up[i];			up[i]=h[u];			if(dfs(u+1,su,sd,depth))			return true;			up[i]=t;//还原现场			flag=false;			break; 		&#125;	&#125;	if(flag)	&#123;		up[su+1]=h[u];		if(dfs(u+1,su+1,sd,depth))		return true;	&#125;	flag=true;	for(int i=1;i&lt;=sd;i++)	&#123;		if(down[i]&gt;h[u])		&#123;			int t=down[i];			down[i]=h[u];			if(dfs(u+1,su,sd,depth))			return true;			down[i]=t;//还原现场2 			flag=false;			break;		&#125;	&#125;	if(flag)	&#123;		down[sd+1]=h[u];		if(dfs(u+1,su,sd+1,depth))		return true;	&#125;	return false;&#125;int main()&#123;	while(cin&gt;&gt;n&amp;&amp;n)//循环输入 	&#123;		for(int i=0;i&lt;n;i++)		cin&gt;&gt;h[i];		int depth=0; 		while(!dfs(0,0,0,depth))//迭代加深 		depth++;		cout&lt;&lt;depth&lt;&lt;endl; 	&#125;	return 0;&#125;
