CSP-S2020题目整理 T1 儒略日 这道题目在考场上卡爆我 然后我就废了 这道题实际上就是考察一个对于闰年和平年的研究 我们可以先预处理前四百年的情况，然后对于在1582年之前的和1582年之后的分类讨论一下，然后这样就可以直接加减了 用一个函数来返回月份的天数似乎比较方便 参考代码 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#define int long longusing namespace std;const int maxn=146097;int q;int y[maxn],m[maxn],d[maxn];int r,tmp;int calc(int year,int month)&#123; if(month==2) &#123; if(year%4!=0) return 28; else &#123; if(year%100!=0) return 29; else &#123; if(year%400!=0) return 28; else return 29; &#125; &#125; &#125; if(month==4||month==6||month==9||month==11) return 30; else return 31;&#125;signed main()&#123; m[0]=d[0]=1; for(int i=1;i&lt;maxn;i++) &#123; d[i]=d[i-1]+1; m[i]=m[i-1]; y[i]=y[i-1]; if(d[i]&gt;calc(y[i],m[i])) &#123; m[i]++,d[i]=1; &#125; if(m[i]&gt;12) &#123; y[i]++; m[i]=1; &#125; &#125; cin&gt;&gt;q; while(q--) &#123; cin&gt;&gt;r; if(r&gt;2299160) &#123; r-=2159351; tmp=r/maxn*400+1200; r%=maxn; &#125; else &#123; tmp=r/1461*4-4712; r%=1461; &#125; cout&lt;&lt;d[r]&lt;&lt;&quot; &quot;&lt;&lt;m[r]&lt;&lt;&quot; &quot;; if(tmp+y[r]&gt;0) cout&lt;&lt;tmp+y[r]; else cout&lt;&lt;(1-tmp-y[r])&lt;&lt;&quot; BC&quot;; cout&lt;&lt;&#x27;
&#x27;; &#125; return 0;&#125; T2 动物园 这道题目我当年在考场看到之后直接就没有去做，没错是的 然后我就光荣爆零了 现在看来，实际上就只是一个位运算的应用，然后题目看起来比较可怕罢了，然后我们的对于这道题 可以用一个数字来记录一下动物的数量，然后需要买的饲料的情况，用二进制就好了 然后我们统计所有的情况，用容斥原理，减去不能怨的动物的数量，剩下的就是还能选的动物的数量啦 注意用一个unsigned long long 和特判 参考代码 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#define int unsigned long longusing namespace std;int n,m,c,k;int ans,dw,ls;signed main()&#123; cin&gt;&gt;n&gt;&gt;m&gt;&gt;c&gt;&gt;k; for(int i=1;i&lt;=n;i++) &#123; int x; cin&gt;&gt;x; dw|=x; &#125; for(int i=1;i&lt;=m;i++) &#123; int p,q; cin&gt;&gt;p&gt;&gt;q; ls|=1ull&lt;&lt;p; &#125; for(int i=0;i&lt;k;i++) if(!((ls&gt;&gt;i)&amp;1)||((dw&gt;&gt;i)&amp;1)) ans++; if(ans==64&amp;&amp;n==0) cout&lt;&lt;&quot;18446744073709551616&quot;&lt;&lt;&#x27;
&#x27;;//特判 else &#123; if(ans==64) cout&lt;&lt;-n&lt;&lt;&#x27;
&#x27;; else cout&lt;&lt;(1ull&lt;&lt;ans)-n&lt;&lt;&#x27;
&#x27;; &#125; return 0;&#125; T3 函数调用 在赛场上我一度认为这道题目是最简单的 但是不是 这道题目看到标签说要用拓扑排序来着 然后拓扑排序一下 实际上对于每个操作进行处理，对于操作2，实际上我们可以看成若干个操作1，然后操作3也可以转化一下，然后我们就可以建一个函数调用关系的有向图，进行拓扑排序，看函数调用的顺序，然后我们对于每一个加法和乘法，看他们对于总的答案的贡献是多少，然后就可做了 参考代码 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;queue&gt;using namespace std;const int maxn=100005;const int mod=998244353;int n,m,q;int cnt[maxn];int a[maxn];int type[maxn],mul[maxn],add[maxn],pos[maxn];int out1[maxn],out2[maxn];vector&lt;int&gt; g1[maxn],g2[maxn];void topo1()&#123; queue &lt;int&gt; q; for(int i=0;i&lt;=m;i++) &#123; out1[i]=g2[i].size(); if(out1[i]==0) q.push(i); &#125; while(q.size()) &#123; int x=q.front(); q.pop(); for(int i=0;i&lt;g1[x].size();i++) &#123; int e=g1[x][i]; mul[e]=1ll*mul[e]*mul[x]%mod; out1[e]--; if(out1[e]==0)q.push(e); &#125; &#125;&#125;void topo2()&#123; queue &lt;int&gt; q; for(int i=0;i&lt;=m;i++) &#123; out2[i]=g1[i].size(); if(out2[i]==0) q.push(i); &#125; while(q.size()) &#123; int x=q.front(); int tag=1; q.pop(); for(int i=g2[x].size();i&gt;0;--i) &#123; int e=g2[x][i-1]; cnt[e]=(cnt[e]+1ll*cnt[x]*tag)%mod; tag=1ll*tag*mul[e]%mod; out2[e]--; if(out2[e]==0) q.push(e); &#125; &#125;&#125;int main()&#123; std::ios::sync_with_stdio(false); cin&gt;&gt;n; for(int i=1;i&lt;=n;i++) cin&gt;&gt;a[i]; cin&gt;&gt;m; mul[0]=1; for(int i=1;i&lt;=m;i++) &#123; cin&gt;&gt;type[i]; if(type[i]==1) &#123; mul[i]=1; cin&gt;&gt;pos[i]&gt;&gt;add[i]; &#125; if(type[i]==2) cin&gt;&gt;mul[i]; if(type[i]==3) &#123; mul[i]=1; int c; cin&gt;&gt;c; for(int j=0;j&lt;c;++j) &#123; int e; cin&gt;&gt;e; g1[e].push_back(i); g2[i].push_back(e); &#125; &#125; &#125; cin&gt;&gt;q; cnt[0]=1; while(q--) &#123; int x; cin&gt;&gt;x; g1[x].push_back(0); g2[0].push_back(x); &#125; topo1(); topo2(); for(int i=1;i&lt;=n;i++) a[i]=1ll*a[i]*mul[0]%mod; for(int i=1;i&lt;=m;i++) &#123; if(type[i]==1) a[pos[i]]=(a[pos[i]]+1ll*cnt[i]*add[i])%mod; &#125; for(int i=1;i&lt;=n;i++) cout&lt;&lt;a[i]&lt;&lt;&quot; &quot;; return 0;&#125; T4 贪吃蛇 讲一个笑话，这是我当初以为整场比赛第二简单的题目 然后我就和这道题目搏斗，与这道题目抗争 最终的结果是我壮烈牺牲 这道题虽然用我的申必贪心方法，样例都能过，但是最后还是爆零了 然后现在看了题解之后，还是有一点懵的 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=1000005;const int inf=1e9;int T,n,a[maxn];pair &lt;int,int&gt; q1[maxn],q2[maxn];int l1,r1,l2,r2;pair &lt;int,int&gt; get_max()//取最大蛇 &#123; if(r1==l1) return q2[l2++]; else if(r2==l2) return q1[--r1]; else if(q2[l2]&gt;q1[r1-1]) return q2[l2++]; else return q1[--r1];&#125;pair &lt;int,int&gt; get_min()//取最小 &#123; if(l1==r1) return q2[--r2]; else if(r2==l2) return q1[l1++]; else if(q2[r2-1]&lt;q1[l1]) return q2[--r2]; else return q1[l1++];&#125;pair &lt;int,int&gt; Min(pair &lt;int,int&gt; x,pair &lt;int,int&gt; y)&#123; return x&lt;y?x:y;&#125;inline void solve()&#123; l1=r1=l2=r2=0; for(int i=1;i&lt;=n;++i) q1[r1++]=make_pair(a[i],i); int flag=0,cnt=0,alf=0; while(1) &#123; cnt++; pair &lt;int,int&gt; x=get_min(),y=get_max(); pair &lt;int,int&gt; z=Min((l1&lt;r1?q1[l1]:make_pair(inf,-inf)),(l2&lt;r2?q2[r2-1]:make_pair(inf,-inf))); y.first-=x.first; if(y&gt;z||cnt==n-1) &#123; if(flag) &#123; cout&lt;&lt;n-(flag-(alf&amp;1))&lt;&lt;&#x27;
&#x27;; return ; &#125; if(cnt==n-1) &#123; cout&lt;&lt;1&lt;&lt;&#x27;
&#x27;; return ; &#125; q2[r2++]=y; &#125; else &#123; alf++; if(!flag) flag=cnt; q2[r2++]=y; &#125; &#125;&#125;int main()&#123; cin&gt;&gt;T; T--; cin&gt;&gt;n; for(int i=1;i&lt;=n;i++) cin&gt;&gt;a[i]; solve(); while(T--) &#123; int k; cin&gt;&gt;k; for(int i=1;i&lt;=k;i++) &#123; int x; cin&gt;&gt;x; cin&gt;&gt;a[x]; &#125; solve(); &#125; return 0;&#125;

【全程NOIP计划】初级数据结构1 在线：每次询问之后，立马可以得到查询结果 离线：知道所有需要查询的值，然后一次输出查询结果 STL中set的用法 用迭代器 并查集 可以支持一些不相交集合的合并和查询 我们可以树形结构来组织数据 同一个集合的元素组成一棵树 因为集合没有交，所以最终构建得到的是一个森林 将树的根节点作为集合的代表元 开始的时候为n个孤立的点 查询一个点所属集合 int get(int x)&#123; return fa[x]=(x==fa[x]? x:get(fa[x]));&#125; 这里做了一个路径压缩，使这颗树变得扁平，大大减小了查找的时间 合并 void merge(int x,int y)&#123; fa[get(x)]=get(y);&#125; 如果是启发式合并的话，是把较小的树插到较大的树 用处 1.可以做最小生成树 也就是kruskal算法 2.还可以用来判环 P3958 奶酪 思路 实际上处理一个上界，处理一个下界，然后判断上面和下面能不能连通就可以了非常简单 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;cstring&gt;#include &lt;algorithm&gt;#include &lt;string&gt;#include &lt;cmath&gt;using namespace std;struct node&#123; long long high,low; long long x,y,z;&#125;;long double dist(node p,node q)&#123; return (long double)sqrt((p.x-q.x)*(p.x-q.x)+(p.y-q.y)*(p.y-q.y)+(p.z-q.z)*(p.z-q.z));&#125;//并查集int f[100010];int get(int x)&#123; return f[x]=(x==f[x]? x:get(f[x]));&#125;void merge(int x,int y)&#123; f[get(x)]=get(y);&#125;void init()&#123; for(int i=1;i&lt;=100000;i++) f[i]=i;&#125;//并查集int T; int main()&#123; cin&gt;&gt;T; while(T--) &#123; init(); long long n,h,r; cin&gt;&gt;n&gt;&gt;h&gt;&gt;r; node a[1005]; for(int i=1;i&lt;=n;i++) cin&gt;&gt;a[i].x&gt;&gt;a[i].y&gt;&gt;a[i].z; int highest[1005]=&#123;0&#125;; int tot1=0; int lowest[1005]=&#123;0&#125;; int tot2=0; for(int i=1;i&lt;=n;i++) &#123; a[i].high=a[i].z+r; a[i].low= a[i].z-r; if(a[i].high&gt;=h) &#123; ++tot1; highest[tot1]=i; &#125; if(a[i].low&lt;=0) &#123; ++tot2; lowest[tot2]=i; &#125; for(int j=i;j&lt;=n;j++) &#123; if(dist(a[i],a[j])&lt;=2*r) merge(i,j); &#125; &#125; bool flag=false; for(int i=1;i&lt;=tot1;i++) &#123; for(int j=1;j&lt;=tot2;j++) &#123; if(get(highest[i])==get(lowest[j])) &#123; flag=true; cout&lt;&lt;&quot;Yes&quot;&lt;&lt;endl; break; &#125; &#125; if(flag) break; &#125; if(flag) continue; else cout&lt;&lt;&quot;No&quot;&lt;&lt;endl; &#125; return 0;&#125; P1197 星球大战 思路 倒序考虑，直接倒序加边，统计连通块就可以了 如果是正序的话要使用非常难的动态图问题 #include&lt;iostream&gt;#include&lt;cstdio&gt;#include&lt;cstring&gt;using namespace std;const int maxn=4e5;struct data&#123; int nxt,to;&#125;e[maxn&lt;&lt;1];int head[maxn],tot;void add(int u,int v)&#123; e[++tot]=(data)&#123;head[u],v&#125;; head[u]=tot;&#125;int f[maxn],n,m,v[maxn],k,a[maxn],cnt,ans[maxn];int find(int x)&#123; return x==f[x]?x:f[x]=find(f[x]);&#125;void dfs(int x)&#123; v[x]=1; for (int i=head[x];i;i=e[i].nxt) &#123; if (!v[e[i].to]) &#123; int f1=find(x),f2=find(e[i].to); if (f1!=f2) f[f1]=f2; dfs(e[i].to); &#125; &#125;&#125;int main()&#123; scanf(&quot;%d%d&quot;,&amp;n,&amp;m); for (int i=0;i&lt;n;++i) f[i]=i; for (int i=0;i&lt;m;++i) &#123; int u,v; scanf(&quot;%d%d&quot;,&amp;u,&amp;v); add(u,v); add(v,u); &#125; scanf(&quot;%d&quot;,&amp;k); for (int i=0;i&lt;k;++i) scanf(&quot;%d&quot;,&amp;a[i]),v[a[i]]=1; for (int i=0;i&lt;n;++i) &#123; if (!v[i]) &#123; cnt++; dfs(i); &#125; &#125; ans[k]=cnt; memset(v,0,sizeof(v)); for (int i=0;i&lt;k;++i) v[a[i]]=1; for (int i=k-1;i&gt;=0;--i) &#123; v[a[i]]=0; cnt++; for (int j=head[a[i]];j;j=e[j].nxt) &#123; if (!v[e[j].to]) &#123; int f1=find(a[i]),f2=find(e[j].to); if (f1!=f2) &#123; f[f2]=f1; cnt--; &#125; &#125; &#125; ans[i]=cnt; &#125; for (int i=0;i&lt;=k;++i) printf(&quot;%d
&quot;,ans[i]); return 0;&#125; P1396 营救 思路 求最大值最小的问题，果断二分答案 也可以开始的时候认为无边，然后从小到大依次加边，直到s和t相连 这里可以使用一个带权并查集 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;string&gt;#include &lt;cstring&gt;#include &lt;queue&gt;using namespace std;struct rec&#123;int x,y,z;&#125;edge[500010];int n,m,s,t;int fa[1000010];bool operator &lt;(rec a,rec b)&#123; return a.z&lt;b.z;&#125;void init()&#123; for(int i=1;i&lt;=1000000;i++) fa[i]=i;&#125;int get(int x)&#123; return fa[x]=(x==fa[x])? x:get(fa[x]);&#125;int main()&#123; init(); cin&gt;&gt;n&gt;&gt;m&gt;&gt;s&gt;&gt;t; for(int i=1;i&lt;=m;i++) cin&gt;&gt;edge[i].x&gt;&gt;edge[i].y&gt;&gt;edge[i].z; sort(edge+1,edge+m+1); for(int i=1;i&lt;=m;i++) &#123; int x=get(edge[i].x); int y=get(edge[i].y); if(x==y) continue; fa[x]=y; if(get(s)==get(t)) &#123; cout&lt;&lt;edge[i].z&lt;&lt;endl; return 0; &#125; &#125; return 0;&#125; P1783 海滩防御 思路 实际上 可以二分，处理两个信号塔的距离，判断他们整个是否连通即可 类似于奶酪，也类似于营救， 还可以用最短路，然后找最短路里面一条最大路径 #include&lt;iostream&gt;#include&lt;cstdio&gt;#include&lt;cmath&gt;#include&lt;queue&gt;#include&lt;cstring&gt;using namespace std;const int maxn = 1005;const double eps=1e-4;int n,m;int x[maxn],y[maxn];int vis[maxn];double dis[maxn][maxn];queue&lt;int&gt; q;int check(double mid)&#123; memset(vis,0,sizeof(vis)); vis[0]=1; q.push(0); while(!q.empty()) &#123; int v=q.front();q.pop(); for(int i=1;i&lt;=m+1;i++) &#123; if(!vis[i]) &#123; if(i==m+1||v==0) &#123; if(dis[v][i]&lt;=mid) vis[i]=1,q.push(i); &#125; else if(dis[v][i]&lt;=2*mid) vis[i]=1,q.push(i); &#125; &#125; &#125; return vis[m+1];&#125;int main()&#123; scanf(&quot;%d%d&quot;,&amp;n,&amp;m); for(int i=1;i&lt;=m;i++) &#123; scanf(&quot;%d%d&quot;,&amp;x[i],&amp;y[i]); dis[0][i]=dis[i][0]=x[i]; dis[m+1][i]=dis[i][m+1]=n-x[i]; &#125; dis[0][m+1]=(1&lt;&lt;30); for(int i=1;i&lt;=m;i++) for(int j=i+1;j&lt;=m;j++) dis[i][j]=dis[j][i]=sqrt((x[i]-x[j])*(x[i]-x[j])+(y[i]-y[j])*(y[i]-y[j])); double l=0,r=10005,ans,mid; while(r-l&gt;=eps) &#123; mid=(l+r)/2; if(check(mid)) r=mid,ans=mid; else l=mid; &#125; printf(&quot;%.2lf&quot;,ans); return 0;&#125; 单调栈与单调队列 单调栈即满足单调性的栈结构，只在一端进行进出 单调队列是满足单调性的队列结构，通常队首只能出，队尾可以进，也可以出（这是deque） 如何维护？ push的时候把不满足单调性的点全部pop掉 要让所有比我高的人给赶走 单调栈的本质是单调队列的退化 单调栈可以求出每个数前方或者后方比它大或者小的第一个数，以及该区间内最大的或者最小值 可以看出，求单调栈任意前缀最大或者最小值可以直接前缀和处理 求每个数前方或者后方比它大或者比它小的第一个数的时候往往没有区间约束 因此单调栈和单调队列解决的问题往往不同 单调队列模板 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;int n,k;int a[1000005],q[1000005];int main()&#123; cin&gt;&gt;n&gt;&gt;k; for(int i=0;i&lt;n;i++) cin&gt;&gt;a[i]; int hh=0,tt=-1; for(int i=0;i&lt;n;i++) &#123; if(hh&lt;=tt&amp;&amp;q[hh]&lt;i-k+1) hh++; while(hh&lt;=tt&amp;&amp;a[q[tt]]&gt;=a[i]) tt--; q[++tt]=i; if(i&gt;=k-1) cout&lt;&lt;a[q[hh]]&lt;&lt;&quot; &quot;; &#125; cout&lt;&lt;endl; hh=0,tt=-1; for(int i=0;i&lt;n;i++) &#123; if(hh&lt;=tt&amp;&amp;q[hh]&lt;i-k+1) hh++; while(hh&lt;=tt&amp;&amp;a[q[tt]]&lt;=a[i]) tt--; q[++tt]=i; if(i&gt;=k-1) cout&lt;&lt;a[q[hh]]&lt;&lt;&quot; &quot;; &#125; cout&lt;&lt;endl; return 0;&#125; 单调栈模板 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;stack&gt;using namespace std;const int maxn=3000005;int n;int a[maxn],f[maxn];stack &lt;int&gt; s;int main()&#123; std::ios::sync_with_stdio(false); cin&gt;&gt;n; for(int i=1;i&lt;=n;i++) cin&gt;&gt;a[i]; for(int i=n;i&gt;=1;i--) &#123; while(s.size()&amp;&amp;a[s.top()]&lt;=a[i]) s.pop(); f[i]=s.empty()? 0:s.top(); s.push(i); &#125; for(int i=1;i&lt;=n;i++) cout&lt;&lt;f[i]&lt;&lt;&quot; &quot;; cout&lt;&lt;&#x27;
&#x27;; return 0;&#125; P1318 积水面积 题目 给定一个非负整数表示每个宽度为1的柱子的高度图 计算次排列的柱子，下雨之后可以接多少雨水 思路 从左向右思考这个问题，我们要想，能不能找到一种东西来维护她存了多少雨水 用单调栈啊！ 利用单调栈来处理就可以了 实际上也很简单 P1106 删数问题 题目 键盘输入一个高精度的整数N，不超过250位，去掉其中任意k个数字后剩下的数字按左右次序将组成一个新的非负整数，变成给定N和k，寻找一种方法使得到的数字组成的新数最小 思路 目标是首位尽可能地小，然后次位尽可能小 也就是说，尽可能地保证高位更小 我们要维护一个单调递增的单调栈 很简单 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;stack&gt;using namespace std;stack &lt;int&gt; s;char a[500];int b[500];int c[500],cnt=0;int k;int main()&#123; scanf(&quot;%s&quot;,a+1); cin&gt;&gt;k; int lena=strlen(a+1); for(int i=1;i&lt;=lena;i++) b[i]=(int)(a[i]-&#x27;0&#x27;); for(int i=1;i&lt;=lena;i++) &#123; while(b[i]&lt;c[cnt]&amp;&amp;k&gt;0) &#123; c[cnt]=0; cnt--; k--; &#125; cnt++; c[cnt]=b[i]; &#125; bool flag=false; while(k--) &#123; c[cnt]=0; cnt--; &#125; for(int i=1;i&lt;=cnt;i++) &#123; if(cnt==1) cout&lt;&lt;c[i]; if(c[i]!=0) flag=true; if(flag==false&amp;&amp;c[i]==0) continue; cout&lt;&lt;c[i]; &#125; cout&lt;&lt;endl; return 0;&#125; P1823 Patrik 音乐会的等待 题目 一个队伍，如果两个人相邻或者两个人中间的人都比他们矮，那他们就可以互相看见对方，问你有多少对人可以相互看到？ 思路 单调栈 尝试构造一个单调递减的单调栈，b可以看到比他高的第一个人，还可以看到所有比它矮的人 如果后面再来一个人，如果比b矮的话，b前面的人它全都看不到 每个节点只计算他左边看到的人 这样不会重复 然而需要处理很多细节 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;stack&gt;using namespace std;const int maxn=500005;int n;int a[maxn];long long ans=0;stack &lt;pair&lt;int,int&gt; &gt; s;int main()&#123; cin&gt;&gt;n; for(int i=0;i&lt;n;i++) &#123; int x; cin&gt;&gt;x; pair &lt;int,int&gt; p(x,1); for( ;(s.size()&amp;&amp;s.top().first&lt;=x);s.pop()) &#123; ans+=s.top().second; if(s.top().first==x) p.second+=s.top().second; &#125; if(s.size()) ans++; s.push(p); &#125; cout&lt;&lt;ans&lt;&lt;endl; return 0;&#125; P3957 跳房子 思路 至少为k，实际上就是分数的最小值大于等于k，很明显，需要二分答案 在加一个单调队列 二分一个g 用动态规划和二分 f[i]=max(f[i−d−g] to f[i−d+g])f[i]=max(f[i-d-g] \space to \space f[i-d+g])f[i]=max(f[i−d−g] to f[i−d+g]) 时间复杂度是O(n2logn)O(n^2logn)O(n2logn)的 我们可以使用单调队列优化 如何维护它的最值呢？ 我们需要维护一个区间长度为2g的序列 现在的问题就变成了如何把右端点向右移一格（这个和单调栈相同） 和如何把左端点向右，然后我们要判断当前区间的最大值是不是被pop出去 而新的最大值就在下一个了 动态规划的复杂度就从O(n2)O(n^2)O(n2)变成了O(n)O(n)O(n) 总的时间复杂度就变成了O(nlogn)O(nlogn)O(nlogn) #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=500005;int n,d,k;int x[maxn],s[maxn];long long ans=0;int f[maxn],q[maxn];bool check(int xl,int xr)&#123; memset(f,-1,sizeof(f)); memset(q,0,sizeof(q)); f[0]=0; int i,j=0; int head=1,last=0; for(i=1;i&lt;=n;i++) &#123; while(x[i]-x[j]&gt;=xl&amp;&amp;j&lt;i)//单调队列判断边界 &#123; if(f[j]!=-1) &#123; while(head&lt;=last&amp;&amp;f[q[last]]&lt;=f[j])//保证队首的都比队尾的大 last--; q[++last]=j; &#125; j++; &#125; while(head&lt;=last&amp;&amp;x[i]-x[q[head]]&gt;xr) head++; if(head&lt;=last) f[i]=f[q[head]]+s[i]; &#125; for(int i=1;i&lt;=n;i++) if(f[i]&gt;=k) return true; return false;&#125;int main()&#123; cin&gt;&gt;n&gt;&gt;d&gt;&gt;k; long long sum=0; for(int i=1;i&lt;=n;i++) &#123; cin&gt;&gt;x[i]&gt;&gt;s[i]; if(sum!=-717&amp;&amp;s[i]&gt;0) sum+=s[i]; if(sum&gt;=k) sum=-717; &#125; if(sum!=-717) &#123; cout&lt;&lt;-1&lt;&lt;&#x27;
&#x27;; return 0; &#125; int l=0,r=x[n]; while(l&lt;=r) &#123; int mid=(l+r)&gt;&gt;1; int xl,xr; if(mid&gt;=d) xl=1; else xl=d-mid; xr=d+mid; if(check(xl,xr)) ans=mid,r=mid-1; else l=mid+1; &#125; cout&lt;&lt;ans&lt;&lt;&#x27;
&#x27;; return 0;&#125; 倍增 简单来说，倍增是一种每次翻倍的计算方式，任何翻倍算法都可以算作倍增 常见的是翻两倍的二倍增 倍增常见的应用是通过当前2i2^i2i的状态，推出2i+12^{i+1}2i+1的状态 提高组常见的倍增求LCA，RMQ等 倍增求RMQ 可以利用倍增算法来构造一个ST表来求区间最大值和最小值 预处理复杂度O(nlogn)O(nlogn)O(nlogn)，查询区间最值的复杂度为O(1)O(1)O(1) 总的复杂度就是O(nlogn)O(nlogn)O(nlogn) 我们有一个长度为n的序列，我们可以设f[i][x]f[i][x]f[i][x]表示从第x个数开始，长度为2i2^i2i的一段数的最值，这个区间的右端点是x+2i−1x+2^i-1x+2i−1，可以得到一个式子 f[i][x]=min/max(f[i−1][x],f[i−1][x+2i]) f[i][x]=min/max(f[i-1][x],f[i-1][x+2^i]) f[i][x]=min/max(f[i−1][x],f[i−1][x+2i]) 这样就可以利用f[i−1][]f[i-1][]f[i−1][]来推导f[i][]f[i][]f[i][]了 对于查询[l,r][l,r][l,r]的最值，我们只需要选择两个区间的并起来为[l,r][l,r][l,r]就可以了，即若2i≤r−l+1≤2i+12^i \leq r-l+1 \leq 2^{i+1}2i≤r−l+1≤2i+1，只左端点对其l，右端点对其r，中间有交集就可以了. 模板题P3865(以取最大值为例) #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;cmath&gt; using namespace std;int n,m;int a[100005];int lg[100005]=&#123;-1&#125;;int f[100005][50];int main()&#123; std::ios::sync_with_stdio(false); cin&gt;&gt;n&gt;&gt;m; for(int i=1;i&lt;=n;i++) &#123; cin&gt;&gt;a[i]; lg[i]=lg[i/2]+1; &#125; for(int i=1;i&lt;=n;i++) f[i][0]=a[i]; for(int i=1;i&lt;=lg[n];i++) &#123; for(int j=1;j+(1&lt;&lt;i)-1&lt;=n;j++) f[j][i]=max(f[j][i-1],f[j+(1&lt;&lt;(i-1))][i-1]); &#125; while(m--) &#123; int l,r; cin&gt;&gt;l&gt;&gt;r; int len=lg[r-l+1]; cout&lt;&lt;max(f[l][len],f[r-(1&lt;&lt;len)+1][len])&lt;&lt;endl; &#125; return 0;&#125; P1081 开车旅行 思路 没有思路 我们可以发现问题1是n个问题2，我们可以对问题1有一个专门的解决方案，但是我们一旦解决了问题2，我们就一定可以解决问题1 首先，数据不是非常大 如果我们只是模拟的话，也可以在O(n2)O(n^2)O(n2)的时间内完成 我们直接用模拟可以写出50分的数据 预处理A和B在每一个城市的决策：使用set（insert进入，然后用upper找到比它大的第一个点，第二个点，和比它小的第一个第二个点），a&lt;b&lt;x&lt;c&lt;da&lt;b&lt;x&lt;c&lt;da&lt;b&lt;x&lt;c&lt;d，这样找出离他最近的第一个点和第二个点，然后使用双向链表巧妙计算，a&lt;−&gt;b&lt;−&gt;x&lt;−&gt;c&lt;−&gt;da&lt;-&gt;b&lt;-&gt;x&lt;-&gt;c&lt;-&gt;da&lt;−&gt;b&lt;−&gt;x&lt;−&gt;c&lt;−&gt;d 当A到达某个点的时候，后面的情况都是不变的 然后使用动态规划处理所有的情况 设f[i][j][k]f[i][j][k]f[i][j][k]表示以i为起点，k第一个开车，开车j天到达的目的地 设fa[k][i][j],fb[k][i][j]fa[k][i][j],fb[k][i][j]fa[k][i][j],fb[k][i][j]表示以i为起点，k第一个开车，开着j天，A和B分别行驶的距离 使用倍增优化，j表示2j2^j2j天，这是，j的空间就不是n了，而是logn 然后算出所有开车的可能性，最后进行开车的模拟就完成了 P7167 Fountain 思路 设f[i][j]f[i][j]f[i][j]表示从i开始流2j2^j2j个盘子需要多少水 用加一个单调递减的单调栈来判断水向哪里流 这样就可以构建出一棵树，进行树上倍增来处理快速查询 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;stack&gt;#define int long longusing namespace std;const int maxn=100005;const int inf=1e16;int n,q,d[maxn],c[maxn];stack&lt;int&gt;s;int l[maxn],first[maxn],en=0;struct edge &#123; int next,e;&#125;edge[maxn];inline void add(int x,int y) &#123; edge[++en].e=y; edge[en].next=first[x]; first[x]=en;&#125;int f[maxn][21],g[maxn][21],dep[maxn];inline void dfs(int u,int fa) &#123; dep[u]=dep[fa]+1; f[u][0]=fa; g[u][0]=c[fa]; for(int i=1;(1&lt;&lt;i)&lt;=dep[u];i++) f[u][i]=f[f[u][i-1]][i-1],g[u][i]=g[f[u][i-1]][i-1]+g[u][i-1]; for(int i=first[u];i;i=edge[i].next) &#123; int v=edge[i].e; dfs(v,u); &#125;&#125;signed main() &#123; cin&gt;&gt;n&gt;&gt;q; for(int i=1;i&lt;=n;i++) cin&gt;&gt;d[i]&gt;&gt;c[i]; d[n+1]=inf; c[n+1]=inf; s.push(1); for(int i=2;i&lt;=n+1;i++) &#123; while (s.size()&amp;&amp;d[i]&gt;d[s.top()]) &#123; l[s.top()]=i; s.pop(); &#125; s.push(i); &#125; for(int i=1;i&lt;=n;i++) add(l[i],i); dfs(n+1,0); for(int i=1;i&lt;=q;i++) &#123; int r,v; cin&gt;&gt;r&gt;&gt;v; if (c[r]&gt;=v) &#123; cout&lt;&lt;r&lt;&lt;endl; continue; &#125; v-=c[r]; int x=r,ans=0; for(int i=20;i&gt;=0;i--) &#123; if (g[x][i]&lt;=v&amp;&amp;(1&lt;&lt;i)&lt;=dep[x]) &#123; v-=g[x][i]; x=f[x][i]; &#125; if (v==0) ans=x; &#125; if (ans==0) ans=f[x][0]; if (ans==n+1) cout&lt;&lt;0&lt;&lt;endl; else cout&lt;&lt;ans&lt;&lt;endl; &#125; return 0;&#125; 堆 大根堆：父亲一定比儿子大的完全二叉树 小根堆：父亲一定比儿子小的完全二叉树 完全二叉树：除了最底层的以外，其他的节点都有两个儿子，且最底层的节点全部靠左 根节点永远是最大（最小）的 但它并不符合二叉搜索树 堆的操作 插入： 在当前堆的最后插入，向上调节到根 调节就不断地和它的父亲互换，然后向上调节就可以了，且调整完了之后一定还是大根堆 删除 只能删除根节点 删除了最大的节点相当于pop，然后根没了 怎么办？ 将最后一个节点变成根节点 和插入类似，我们可以把根不断向节点调整，调整完了之后一定是大根堆 优先队列本质上就是一个堆 #include &lt;queue&gt;std::priority_queue &lt;int&gt; qq.push(x),q.pop等等 优先队列如何使每次查询的是最小的数？ 我们用以下声明方式声明一个小根堆 priority_queue &lt;int,vector&lt;int&gt;,greater&lt;int&gt;&gt; q; 实际上还可以直接插入负数 Dijkstra堆优化的时候使用 priority_queue &lt;pair&lt;int,int&gt; &gt;,vector&lt;pair&lt;int,int&gt;,great&lt;pair&lt;int,int&gt; &gt; &gt; 堆排序 利用堆的根节点最大和完全二叉树的性质 步骤 在原序列建立一个大根堆 void update(int x,int m)&#123; int t=lson(x); if(t&gt;m) return ; if(t&lt;m&amp;&amp;a[t+1]&gt;a[t]) t++; if(a[t]&gt;a[x]) swap(t,m);&#125;void heap_sort()&#123; for(int i=n;i&gt;=1;i--) update(1,n);//建立大根堆 for(int i=n-1;i&gt;=1;i--) &#123; swap(a[i+1],a[i]);//依次取出 update(1,i); &#125;&#125; 建立大根堆O(n)O(n)O(n)，依次取出O(logn)O(logn)O(logn) 找第k大的数，复杂度O(n+klogn)O(n+klogn)O(n+klogn)，当k远小于n的时候用堆排的优势非常明显，并且堆排是稳定的 P2827 蚯蚓 思路 Trie树 trie树的中文译名为字典树 字典树是边权为字符串的树，一个节点代表一个字符串 所有节点表示已知串和已知串的所有前缀 建树 如果没有就加，如果有，就向下查找下一个有没有，然后在最后一个 节点打一个标记 应用 1.检索字符串（是否出现，出现次数计数）(相当于手动完成了map[string])的功能，但它比map[string]快得多。 2.维护和前缀有关的一些事情，找两个字符串的公共前缀 3.AC自动机 板子 struct Trie&#123; long long val[maxn],ch[maxn][26],size; Trie() &#123; size=1; memset(ch[0],0,sizeof(ch[0])); memset(val,0,sizeof(val)); &#125; long long index(char c) &#123; return c-&#x27;a&#x27;; &#125; void insert(char s[]) &#123; long long u=0,len=strlen(s+1); for(int i=1;i&lt;=len;i++) &#123; long long c=index(s[i]); if(!ch[u][c]) &#123; memset(ch[size],0,sizeof(ch[size])); ch[u][c]=size++; &#125; u=ch[u][c]; &#125; &#125; long long search(char s[]) &#123; long long u=0,len=strlen(s+1); for(int i=1;i&lt;=len;i++) &#123; long long c=index(s[i]); if(!ch[u][c]) return 0; u=ch[u][c]; &#125; if(!val[u]) &#123; val[u]=1; return 1; &#125; return 2; &#125;&#125;tree; P2580 于是他错误地点名开始了 思路 记录一个字符串的权值是不是第一次出现 当我们发现名字不存在的时候，我们找的时候就没有他的前缀，直接就认为他不存在 实际上就是板子修改一下，没啥区别 P5629 区间与除法 思路 建立一个trie树 就可以了

【全程NOIP计划】分治与倍增 分治 分治就是分而治之，化整为零的思想 分治的原理是把困难的大问题化解为简单的小问题 然后先解决小问题，然后根据小问题的答案解决大问题 它本质上不是一个算法，而是一个思想 比如快速幂，倍增求lca，归并排序，线段是cdq分治，甚至后缀数组FFT都利用了分治思想 分治虽然不经常出题，但是也非常有用 快速幂 快速幂可以在O(logb)O(logb)O(logb)的时间复杂度内计算aba^bab 方法很简单 注意到如果b是偶数，那么就可以先计算ab2a^{ rac{b}{2}}a2b​,这样问题的规模就减少了一半 如果b是奇数，那么我们就可以计算ab2a^{ rac{b}{2}}a2b​平方之后再乘a，问题规模同样以不大的代价减少了一般 这里的aba^bab就是大问题，而ab2a^{ rac b 2}a2b​就是小问题了 long long f(long long a,long long b,long long c)&#123; long long temp=f(a,b/2) if(b&amp;1) return temp*temp%c; else return temp*temp*a%c;&#125;long long ksm(long long x,long long y,long long z)&#123; long long res=1%p; for( ;y;y&gt;&gt;=1) &#123; if(y&amp;1) res=res*x%z; x=x*x%z; &#125; return res;&#125; 递归实现和迭代实现 实际上都是分治解决的问题，但是方向相反 递归往往是从大问题开始，慢慢递归到小问题，然后进行合并 迭代呢就是要先解决好小问题，从最小的解决，并不断合并得到大问题 从后面的二分和归并排序，还有cdq分治都可以看到这一点 P1045 麦森数 题目 输出2p−12^{p-1}2p−1的后五百位数 思路 这里有一个神奇的数学技巧，但是这里用高精度加快速幂就可以了 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;cmath&gt;using namespace std;unsigned long long a[505]=&#123;1&#125;;int main()&#123; int p; cin&gt;&gt;p; cout&lt;&lt;(int)(p*log10(2))+1&lt;&lt;&#x27;
&#x27;; for( ;p&gt;0;p-=60) &#123; unsigned long long f=0; for(int i=0;i&lt;500;i++) &#123; if(p&gt;60) a[i]&lt;&lt;=60; else a[i]&lt;&lt;=p; a[i]+=f; f=a[i]/10; a[i]%=10; &#125; &#125; a[0]-=1; for(int i=499;i&gt;=0;i--) &#123; cout&lt;&lt;(char)(a[i]+&#x27;0&#x27;); if(i%50==0) cout&lt;&lt;&#x27;
&#x27;; &#125; return 0;&#125; 快速幂的特别用途 计算模意义下的出发 根据费马小定理 如果模数p为质数，那么a模p意义下的逆元就是ap−2a^{p-2}ap−2 也就是说a∗ap−2mod p=1a*a^{p-2}mod\space p=1a∗ap−2mod p=1 如果给一个数乘以一个ap−1a^{p-1}ap−1,就相当于在模p意义下给这个数除了一个a 在一些计数题目或者期望计算题目中，由于数值可能比较大或者精度比较大，出题人都会让你输出模p意义下的答案 P1850 换教室 思路 这道题目一个期望DP 期望就是数学期望 它的物理意义是，假设一个随机事件执行无穷次，这个随机事件结果的平均值就是期望 公式定义是∑P(x)f(x)\sum P(x) f(x)∑P(x)f(x),也就是说吧所有可能出现的值成圣这个值出现的概率，再加起来 那么们就会注意到，事件x发生的概率为P(x)P(x)P(x)，一般来说是一个分数，可能出现的的次数除总次数 那么如果在模质数意义下输出期望，计算P(x)P(x)P(x)的时候最好使用快速木和费马小定理来做除法 P4071 排列计数 题目 求有多少种1到n的排列a，慢慢组序列恰好有m个位置i，使得ai=ia_i=iai​=i 答案对109+710^9+7109+7取模 思路 这个题需要先进性一系列的数学推导 我们只需要知道最后的答案一长串 最后用的时候要用快速幂就对了 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#define int long longusing namespace std;const long long maxn=1000005,p=1e9+7;int T;long long f[maxn];long long inv[maxn],d[maxn];inline int read()&#123; int x=0,f=1;char ch=getchar(); while (ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if (ch==&#x27;-&#x27;) f=-1;ch=getchar();&#125; while (ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=x*10+ch-48;ch=getchar();&#125; return x*f;&#125;long long ksm(long long a,long long b,long long p)&#123; long long ans=1%p; for( ;b;b&gt;&gt;=1) &#123; if(b&amp;1) ans=(long long)ans*a%p; a=(long long)a*a%p; &#125; return ans;&#125;signed main()&#123; T=read(); f[0]=1; for(int i=1;i&lt;maxn;i++) &#123; f[i]=f[i-1]*i%p; inv[i]=ksm(f[i],p-2,p);//快速幂求逆元 &#125; d[1]=0,d[2]=1,d[3]=2; for(int i=4;i&lt;maxn;i++) d[i]=(i-1)*(d[i-1]+d[i-2])%p; while(T--) &#123; int n=read(),m=read(); if(n==m+1) cout&lt;&lt;0&lt;&lt;&#x27;
&#x27;; else if(m==n) cout&lt;&lt;1&lt;&lt;&#x27;
&#x27;; else if(m==0) cout&lt;&lt;d[n]&lt;&lt;&#x27;
&#x27;; else cout&lt;&lt;(long long)(f[n]*inv[m]%p*inv[n-m]%p*d[n-m]%p)&lt;&lt;&#x27;
&#x27;; &#125; return 0;&#125; 归并排序 三大基本排序：选择排序，冒泡排序和归并排序 其中的归并排序不仅仅是一个排序的方式，它的分治思想要在其他地方思想 分治排序的方法 首先调用f(l,r)f(l,r)f(l,r),然后将l,r划分为两个子问题[l,mid]和[mid+1,r][l,mid]和[mid+1,r][l,mid]和[mid+1,r] 对于左右两半区间分别排序排好之后，再把两个排好序的区间合并为一个大的有序区间，这个区间合并是比较好做的，因为如果从小向大向大的区间里面填数，那么每次一定从两个小区间的最小端取数，只需要从两个最小值中选取高呢更小的那个，然后放进大区间里面 和快速幂类似，每次分治都会使问题的规模减少至少一半 一次你至多logn次分值之后区间长度就会减少为1 这时子问题就非常容易解决了，长度为1的区间是根本不需要排序的 整个归并排序就是不断把大问题分成小问题，直至小问题非常容易解决为止，再逐步把小问题变成大问题，合并，就非常简单了 代码（求逆序对） int cnt=0;int q[41000];void f(int l,int r)&#123; if(l&gt;=r) return ; int mid=(l+r)&gt;&gt;1; f(l,mid),f(mid+1,r); int head1=l,head2=mid+1; for(int i=l;i&lt;=r;i++) &#123; if(head2&lt;=r &amp;&amp;(head1&gt;mid||a[head2]&lt;a[head1])) q[i]=a[head2++]; else q[i]=a[head1++],cnt+=(head2-mid-1); &#125; for(int i=1;i&lt;=r;i++) a[i]=q[i]; return ;&#125; 主定理与渐进符号 假设有递归式T(n)=aT(n/b)+f(n)T(n)=aT(n/b)+f(n)T(n)=aT(n/b)+f(n)，f(n)f(n)f(n)为递归外的，其中n是问题规模，a是递推子问题数量，n/b是每个子问题的规模 有以下三条 1.若f(n)=O(nlogba−ϵ)，ϵ&gt;0f(n)=O(n^{log_b^a-\epsilon})，\epsilon&gt;0f(n)=O(nlogba​−ϵ)，ϵ&gt;0那么则T(n)=Θ(nlogba)T(n)=\Theta(n^{log_b^a})T(n)=Θ(nlogba​) 2.若f(n)=Θ(nlogba)f(n)=\Theta(n^{log_b^a})f(n)=Θ(nlogba​)那么T(n)=Θ(nlogbalogn)T(n)=\Theta(n^{log_b^a}logn)T(n)=Θ(nlogba​logn) 3.若f(n)=Ω(nlogba+ϵ),ϵ&gt;0f(n)=\Omega(n^{log_b^a+\epsilon}),\epsilon&gt;0f(n)=Ω(nlogba​+ϵ),ϵ&gt;0,且对于某个常数，C&lt;1和所有充分大的n有af(nb)≤cf(n)af( rac n b)\leq cf(n)af(bn​)≤cf(n)，那么T(n)=Θ(f(n))T(n)=\Theta(f(n))T(n)=Θ(f(n)). 正如上面，有一些符号并不是原来的符号，因为我打不出来， 渐进符号正如其名，随着问题规模n不断增加，计算量h(n)的增加速度不小于f(n)，不大于f(n)，或者几乎和f(n)一样 而并不是说计算量近似等于f(n)，因为当n比较小的时候，可能会出现计算量远远超过f(n)的情况 此外，在渐进符号里面有三种意义不同的符号：O,Θ,ΩO,\Theta ,\OmegaO,Θ,Ω 这些都是渐进符号，对于前两个符号，他们经常在复杂度分析中出现 O(f(n))O(f(n))O(f(n))的就是指问题的复杂度不超过f(n)f(n)f(n),即O规定了问题的上界 Ω(f(n))\Omega(f(n))Ω(f(n))指问题的复杂度不小于f(n)f(n)f(n)，即Ω\OmegaΩ规定了问题的下界 而当复杂度同时满足O(f(n))O(f(n))O(f(n))和Ω(f(n))\Omega(f(n))Ω(f(n))的时候，我们就说问题的复杂度满足Θ(f(n))\Theta(f(n))Θ(f(n)) 我们再来看一下主定理 第一条和第三条的ϵ\epsilonϵ其实是为了严谨做出出的修正，我们意会的时候可以忽略他们 这样三条定理就可以理解为 1.如果分治外的操作不比nlogban^{log_b^a}nlogba​多，那么总的复杂度久违Θ(nlogab)\Theta (n^{log_a^b})Θ(nlogab​),更近一步地，可以理解为如果分治外的操作比分治操作增速更慢，那么分治操作占主要复杂度 2.如果分治外的操作数量级和nlogban^{log_b^a}nlogba​相当，那么总的复杂度Θ(nlogbalogn)\Theta(n^{log_b^a}logn)Θ(nlogba​logn)，这是最常见的情况，如果数量级相当，那么总的复杂度还要乘上一个lognlognlogn 3.如果分治外的操作数量级不比nlogban^{log_b^a}nlogba​小，那么当n很大的时候，总的复杂度会趋向于Θ(f(n))\Theta(f(n))Θ(f(n))，也就是说，如果分治外的操作非常慢，那么算法就会被这些操作占主导，分治的作用减弱 归并排序的复杂度分析 回到归并排序，首先分治排序的b和a都是2，也就是说问题规模每次减少一半，问题数量每次增加一倍 那么分治外的操作就要和Θ(nlog22)\Theta(n^{log_2^2})Θ(nlog22​)也就是Θ(n)\Theta(n)Θ(n)来相比 显然，把两半序列合并成一个序列，n个元素中的每一个都要访问到 因此，分治外操作的复杂度为Θf(n)\Theta f(n)Θf(n) 所以根据主定理，归并排序的总复杂度就是Θ(nlogn)\Theta(nlogn)Θ(nlogn)的 现在你知道nlognnlognnlogn的复杂度是怎么来的了 话说，如果是三分归并排序呢？ 速度会更快，但是复杂度并没有变 更快地原因是因为递归层数会降低，但是复杂度还是由主定理算出来的 a=3,b=3,f(n)=na=3,b=3,f(n)=na=3,b=3,f(n)=n 那么主定理就告诉我们,T(n)=Θ(nlogn)T(n)=\Theta(nlogn)T(n)=Θ(nlogn) 但是层数不是降为log3nlog_3^nlog3n​了吗？ 事实上，三分之后Θ(nlog3n)=Θ(nlognlog32)=Θ(nlogn)\Theta(nlog_3^n)=\Theta( rac{nlogn}{log_3^2})=\Theta(nlogn)Θ(nlog3n​)=Θ(log32​nlogn​)=Θ(nlogn) 这里用了换底公式，因为log32)log_3^2)log32​)是一个常数，在复杂度中不分析 P1908 逆序对 题目 给你一个序列a，长度为n，问你其中逆序对的长度 思路 这里使用归并排序来做 此外还可以用树状数组，线段树等来做 但他们的做法都没有分治优秀 我们还是把大问题分成小问题 f(l,r)f(l,r)f(l,r)表示求区间内[l,r][l,r][l,r]内部的逆序对个数，而f(l,r)f(l,r)f(l,r)被分解为f(l,mid)f(l,mid)f(l,mid)和f(mid+1,r)f(mid+1,r)f(mid+1,r)两个小问题来解决 不如假设f(l,mid)f(l,mid)f(l,mid)和f(mid+1，r)f(mid+1，r)f(mid+1，r)都已经成功解决了 那么我们知道了左半边的逆序对个数，右半边的逆序对个数，现在需要考虑的只有一个在左边，一个在右边的逆序对个数 实际上非常好解决 归并排序的做法就是把两边中剩余中最小的数选取一个放到大区间中 当右边的一个数加入到大区间时，它对答案的贡献就是左边剩下的逆序对数 因为左边剩下的数字都比它大，并且都比它左 这样就可以统计跨左右两边的逆序对的个数，结合左边的逆序对个数和右边的逆序对个数，我们就可以得到整个区间的逆序对个数 然后继续将答案向上传递，就是这样就解决了 但是如果他们没有成功完成咋办？ 可以证明它们成功完成了
数学归纳法： 1.f(k,k)f(k,k)f(k,k)显然正确 2.如果f(l,mid)f(l,mid)f(l,mid)和f(mid+1,r)f(mid+1,r)f(mid+1,r)正确，那么f(l,r)f(l,r)f(l,r)正确 3.归纳可得f(1,n)f(1,n)f(1,n)成立
代码见上归并排序 本人有一种树状数组的写法 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=500005;int tree[maxn],rank[maxn],n;long long ans;struct point&#123; int num,val;&#125;a[maxn];int lowbit(int x)&#123; return x&amp;(-x);&#125;bool cmp(point q,point w)&#123; if(q.val==w.val) return q.num&lt;w.num; return q.val&lt;w.val;&#125;void add(int x,int y)&#123; for( ;x&lt;=n;x+=lowbit(x)) tree[x]+=y;&#125;int ask(int x)&#123; int ans=0; for( ;x;x-=lowbit(x)) ans+=tree[x]; return ans;&#125;int main()&#123; std::ios::sync_with_stdio(false); cin&gt;&gt;n; for(int i=1;i&lt;=n;i++) &#123; cin&gt;&gt;a[i].val; a[i].num=i; &#125; sort(a+1,a+1+n,cmp); for(int i=1;i&lt;=n;i++) rank[a[i].num]=i; for(int i=1;i&lt;=n;i++) &#123; add(rank[i],1); ans+=(i-ask(rank[i])); &#125; cout&lt;&lt;ans&lt;&lt;endl; return 0;&#125; P1966 火柴排队 题目 给你两盒火柴，每盒火柴有n根火柴，每盒火柴的高度不同，一开始两盒火柴是排好序的，现在每次你可以交换相邻两个火柴的顺序，问你最少的交换次数，使∑(ai−bi)2→min\sum(a_i-b_i)^2 ightarrow min∑(ai​−bi​)2→min 思路 公式技巧变换 变形之后式子就变成了一个式子，其中有一个常数，另外有一个∑aibi\sum a_ib_i∑ai​bi​,让这个数最大就可以了 这是一个经典贪心问题，给a，b从小到大排序，然后对应的匹配就好了 因此只要动一边就好了 然后问题就转化为，给你一个原序列x，和一个目标序列t，问你最少多少次变化吧s变化成t需要注意的是，火柴的高度是各不相同的，因此s的位置和t的位置是一一对应的，不存在一个位置可以移动到多个位置的情况 因此问题就可以转化给一个排列s，问多少步可以转化为1,2,3,4……n 这里需要知道一个问题，交换相邻的两个数字，只会让序列的逆序对增加或者减去一个 因为是相邻的两个数的内部交换，因此所有其他的数和他们的顺序关系并没有改变，实际上，只有他们自己的顺序改变了 而要变化到1,2,3……n，我们是不能交换两个顺序的数字的，因为早晚也会换回来，而任何时候又不缺逆序来交换，当没有逆序交换的时候，我们就得到了目标序列 因此整个转化就是不断交换相邻的逆序，每次逆序对-1，最少需要的步数就是逆序对的个数 实际上就是求逆序对个数 我是拿树状数组过掉的 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=500005;const int mod=99999997;int tree[maxn],rank[maxn],n;long long ans;struct point&#123; int num,val;&#125;a[maxn],b[maxn];int lowbit(int x)&#123; return x&amp;(-x);&#125;bool cmp(point q,point w)&#123; if(q.val==w.val) return q.num&lt;w.num; return q.val&lt;w.val;&#125;void add(int x,int y)&#123; for( ;x&lt;=n;x+=lowbit(x)) tree[x]+=y,tree[x]%=mod;&#125;int ask(int x)&#123; int ans=0; for( ;x;x-=lowbit(x)) ans+=tree[x],ans%=mod; return ans;&#125;int main()&#123; std::ios::sync_with_stdio(false); cin&gt;&gt;n; for(int i=1;i&lt;=n;i++) &#123; cin&gt;&gt;a[i].val; a[i].num=i; &#125; for(int i=1;i&lt;=n;i++) &#123; cin&gt;&gt;b[i].val; b[i].num=i; &#125; sort(a+1,a+1+n,cmp); sort(b+1,b+1+n,cmp); for(int i=1;i&lt;=n;i++) rank[a[i].num]=b[i].num; for(int i=1;i&lt;=n;i++) &#123; add(rank[i],1); ans+=(i-ask(rank[i])); ans%=mod; &#125; cout&lt;&lt;ans&lt;&lt;endl; return 0;&#125; CDQ分治 cdq分治一般用于解决涉及到多维偏序的问题 偏序可以简单地理解为大小关系，多维偏序就是对多个维度的大小关系有要求 cdq分治的思想主要是区间分治，然后计算左边对右边区间产生的贡献 实际上，求逆序对就是一个cdq分治 逆序对中的第一位实际上就是数组下表，因为输入是按照下标顺序输入的，所以被我们忽略了 什么叫左边区间右边区间产生贡献呢？ 首先由于这是一个分治的过程，所以我们假设左右两边已经计算完了 因此只需要考虑跨区间的贡献 由于分治开始之前第一位就有序，所以第一位的左半区间一定比右半边区间要小 那么跨区间的点对就自带第一维的大小关系的性质，接下来只需要考虑第二维 如果再有第三维关系，就只能用数据结构了，用树状数组和线段树维护 cdq分治与数据结构的关系 逆序对既可以用归并排序算，也可以用树状数组算 这就是因为值域线段树或者值域树状数组维护的实际上也是一个偏序关系 数据结构相比分治，最大的优势实际上动态维护 也就是说可以随时修改，随时查询，不像离线分治，只能提前知道所有信息，然后统一求解 代价就是常数大，代码长，空间大，而且许多属性维护起来很困难，但是用分治计算就会简单很多 所以不要无脑上数据结构，不妨想想有没有分治的做法 P3810 【模板】三维偏序（陌上花开） 题目 有n个点，在三维空间中坐标为xi,yi,zix_i,y_i,z_ixi​,yi​,zi​，表示他们的位置 现在问你对于每个点iii，有多少个jjj满足xj≤xi,yj≤yi,zj≤zix_j \le x_i ,y_j \le y_i ,z_j \le z_ixj​≤xi​,yj​≤yi​,zj​≤zi​ 思路 二维线段树太难了，空间复杂度太大了，动态开点很麻烦，常数非常大 所以我们还是要用cdq分治 第一维对xxx排序，第二维用归并排序对yyy排序 这样就能找出所有的xj≤xi，yj≤yix_j \le x_i，y_j\le y_ixj​≤xi​，yj​≤yi​的点对，和逆序对的思路是一样的 第三维有权值树状数组维护就可以了，t[i]t[i]t[i]表示坐标iii出现了多少次，然后树状数组能够查询j≤ij\le ij≤i 的t[j]t[j]t[j]的和，也就是找到了zj≤ziz_j \le z_izj​≤zi​的数量 麻烦得是相等的情况比较难处理需要好好想一想 需要好好想想 这道题是省选入门题 以下来自@撤云 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=200005;struct node&#123; int x,y,z,id;&#125;a[maxn];int c[maxn*4],k,n,b[maxn],qyj[maxn],f[maxn];int lowbit(int x)&#123; return x&amp;(-x);&#125;void add(int x,int y)&#123; for( ;x&lt;=k;x+=lowbit(x)) c[x]+=y;&#125;int ask(int x)&#123; int res=0; for( ;x;x-=lowbit(x)) res+=c[x]; return res;&#125;bool cmp1(const node &amp;a,const node &amp;b)&#123; if(a.x!=b.x) return a.x&lt;b.x; if(a.y!=b.y) return a.y&lt;b.y; return a.z&lt;b.z;&#125;bool cmp2(const node &amp;a,const node &amp;b)&#123; if(a.y!=b.y) return a.y&lt;b.y; if(a.z!=b.z) return a.z&lt;b.z; return a.x&lt;b.x;&#125;void cdq(int l,int r)&#123; if(l==r) return ; int mid=(l+r)&gt;&gt;1; int flag; cdq(l,mid),cdq(mid+1,r); sort(a+l,a+r+1,cmp2); for(int i=l;i&lt;=r;i++) (a[i].x&lt;=mid)?add(a[i].z,1),flag=i:b[a[i].id]+=ask(a[i].z); for(int i=l;i&lt;=r;i++) if(a[i].x&lt;=mid) add(a[i].z,-1);&#125;int main()&#123; cin&gt;&gt;n&gt;&gt;k; for(int i=1;i&lt;=n;i++) cin&gt;&gt;a[i].x&gt;&gt;a[i].y&gt;&gt;a[i].z,a[i].id=i; sort(a+1,a+1+n,cmp1); for(int i=1;i&lt;=n; ) &#123; int j=i+1; while(j&lt;=n&amp;&amp;a[j].x==a[i].x&amp;&amp;a[j].y==a[i].y&amp;&amp;a[j].z==a[i].z) j++; while(i&lt;j) qyj[a[i].id]=a[j-1].id,i++; &#125; for(int i=1;i&lt;=n;i++) a[i].x=i; cdq(1,n); for(int i=1;i&lt;=n;i++) f[b[qyj[a[i].id]]]++; for(int i=0;i&lt;n;i++) cout&lt;&lt;f[i]&lt;&lt;&#x27;
&#x27;; return 0;&#125; P2345 MooFest G 题目 数轴上有n头牛，每头牛的坐标为xix_ixi​，听力为yiy_iyi​，如果第i头奶牛和第j头奶牛说话，会发出max(vi,vj)∗∣xi−xj∣max(v_i,v_j)*|x_i-x_j|max(vi​,vj​)∗∣xi​−xj​∣的音量 假设每两头牛都在互相说话，问总的音量大小 思路 太秀了，可以同时跟一堆牛同时说话 先看看题目要求的公式 式子两部分都很麻烦，不管是max还是绝对值都很难大规模快速运算，要想办法拆掉 回想递归分治的过程中，左边区间的某一个维度一定大于右边区间 使我们这样就可以很好地解决式子中的一个 我们一开始先按viv_ivi​排序，这样左边区间的viv_ivi​一定小于右边区间的viv_ivi​，那么跨区间之间的点对，一定是右边的点提供viv_ivi​，这样就可以把max消掉了 绝对值怎么消掉呢？ 既然已经对v排序了，那么归并排序的过程中就要对x排序 之前已经说了很多次了，每当右边的一个点被拿出，那么左边没有被拿出的，x一定大于右边的，而已经被拿出的一定小于左边的 分开计算这两种情况，就把绝对值消掉了 只需要单独统计一下被拿出和没有被拿出的个数，以及被拿出和没有被拿出的坐标和，就可以计算出答案了 void f(int l,int r)&#123; if(l&gt;=r) return ; int mid=(l+r)&gt;&gt;1; f(l,mid); f(mid+1,r); int head1=l,head2=mid+1; long long lsum=0,rsum=0; long long lcnt=0,rcnt=mid-l+1; for(int i=1;i&lt;=mid;i++) rsum+=a[i].x; for(int i=l;i&lt;=r;i++) &#123; if(head2&lt;=r&amp;&amp;(head1&gt;mid||a[head2].x&lt;a[head1].x)) &#123; ans+=a[head2].y*(lcnt*a[head2].x-lsum); ans+=a[head2].y*(rsum-rcnt*a[head2].x); &#125; else &#123; lsum+=a[head1].x; rsum-=a[head1].x; lcnt++; rcnt--; q[i]=a[head1++]; &#125; &#125; for(int i=l;i&lt;=r;i++) a[i]=q[i];&#125;bool cmp(nds,x,nds,y)&#123; return x.y==y.y? x.x&lt;y.x : x.y&lt;y.y;&#125;int main()&#123; scanf(&quot;%d&quot;,&amp;n); for(int i=1;i&lt;=n;i++) scanf(&quot;%d%d&quot;,&amp;a[i].y,&amp;a[i].x); sort(a+1,a+n+1,cmp); f(1,n); printf(&quot;%lld
&quot;,ans); return 0;&#125; 实际上原题是10410^4104级别的数据，暴力也能过掉/kkk #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=20005;int n;int v[maxn],x[maxn];int main()&#123; cin&gt;&gt;n; for(int i=1;i&lt;=n;i++) cin&gt;&gt;v[i]&gt;&gt;x[i]; long long ans=0; for(int i=1;i&lt;=n;i++) &#123; for(int j=i+1;j&lt;=n;j++) ans+=(max(v[i],v[j])*abs(x[i]-x[j])); &#125; cout&lt;&lt;ans&lt;&lt;endl; return 0;&#125; P1228 地毯填补问题 思路 分治你一般是自顶向下，考虑如何把大问题分成小问题 但是这道题必须从小问题入手，考虑如何拓展为大问题 简单模拟k=1，2，3的啥情况 我们可以发现规律 先把整个大巨星分成四块，找到公主在哪块，然后递归地去填这一块 填完之后，把中间2*2剩下的3个块用一个图形填满，然后递归剩下的三个 由于剩下的三块每块恰好有一个，因此我们也可以完全套用之前的做法去解决 更近一步，你可以发现当k=1的时候，这个策略适用 2*2的块可以分成四个块，公主的那一块已经满了，而剩下的三块就是其他情况中的，中间2 乘 2剩下的三个块 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;int x,y;int k;void dfs(int x,int y,int a,int b,int l)&#123; if(l==1) return; if(x-a&lt;=l/2-1&amp;&amp;y-b&lt;=l/2-1) &#123; cout&lt;&lt;a+l/2&lt;&lt;&quot; &quot;&lt;&lt;b+l/2&lt;&lt;&quot; &quot;&lt;&lt;1&lt;&lt;&#x27;
&#x27;; dfs(x,y,a,b,l/2); dfs(a+l/2-1,b+l/2,a,b+l/2,l/2); dfs(a+l/2,b+l/2-1,a+l/2,b,l/2); dfs(a+l/2,b+l/2,a+l/2,b+l/2,l/2); &#125; else if(x-a&lt;=l/2-1 &amp;&amp; y-b&gt;l/2-1) &#123; cout&lt;&lt;a+l/2&lt;&lt;&quot; &quot;&lt;&lt;b+l/2-1&lt;&lt;&quot; &quot;&lt;&lt;2&lt;&lt;&#x27;
&#x27;; dfs(a+l/2-1,b+l/2-1,a,b,l/2); dfs(x,y,a,b+l/2,l/2); dfs(a+l/2,b+l/2-1,a+l/2,b,l/2); dfs(a+l/2,b+l/2,a+l/2,b+l/2,l/2); &#125; else if(x-a&gt;l/2-1 &amp;&amp; y-b&lt;=l/2-1) &#123; cout&lt;&lt;a+l/2-1&lt;&lt;&quot; &quot;&lt;&lt;b+l/2&lt;&lt;&quot; &quot;&lt;&lt;3&lt;&lt;&#x27;
&#x27;; dfs(a+l/2-1,b+l/2-1,a,b,l/2); dfs(a+l/2-1,b+l/2,a,b+l/2,l/2); dfs(x,y,a+l/2,b,l/2); dfs(a+l/2,b+l/2,a+l/2,b+l/2,l/2); &#125; else &#123; cout&lt;&lt;a+l/2-1&lt;&lt;&quot; &quot;&lt;&lt;b+l/2-1&lt;&lt;&quot; &quot;&lt;&lt;4&lt;&lt;&#x27;
&#x27;; dfs(a+l/2-1,b+l/2-1,a,b,l/2); dfs(a+l/2-1,b+l/2,a,b+l/2,l/2); dfs(a+l/2,b+l/2-1,a+l/2,b,l/2); dfs(x,y,a+l/2,b+l/2,l/2); &#125;&#125;int main()&#123; std::ios::sync_with_stdio(false); cin&gt;&gt;k&gt;&gt;x&gt;&gt;y; int qyj=1&lt;&lt;k; dfs(x,y,1,1,qyj); return 0;&#125; P1429 平面最近点对 思路 我们可以用分治来做 首先对其中一个坐标排序，然后就可以按照序列分治的方式 f(l,mid)f(l,mid)f(l,mid)和f(mid+1,r)f(mid+1,r)f(mid+1,r)，负责解决两边区间内部的贡献，接下来只需要考虑跨过中线的贡献 不难想象，最近点对一定不会离这个中线很远，而且距离中线的距离一定会小于两边内部的最短距离 然后两两枚举左右两边的点对计算距离 因此这样能显著加速 但是还是无法解决一个极端情况 就是两边的点横坐标非常集中，还是容易被卡成n2n^2n2 怎么办？ 首先，对于左边的一个点(x,y)(x,y)(x,y)，假设左右两边区间内部的最近点对距离为d 右边的点坐标范围必须在(mid,y−d)(mid,y-d)(mid,y−d)到(mid+d,y+d)(mid+d,y+d)(mid+d,y+d)这样一个d*2d的长方形上 朝珠这个范围的点一定没有比d大的，否则就没有意义了 然后很容易知道，在这样一个d*2d的长方形之内，至多有六个点 因为如果超过6个点，则无论如何分配点的位置，距离都会小于d 因此需要枚举每一个左边的点，再枚举右边对应方形内的点，就可以把分治外操作的复杂度压缩到f(n)=O(n)f(n)=O(n)f(n)=O(n) 这样用主定义算出来的总的复杂度就是O(nlogn)O(nlogn)O(nlogn) 发现直接用快排加黑科技也很牛逼 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;cmath&gt; using namespace std;const int maxn=200005;int n;double x[maxn],y[maxn];int per[maxn];inline int read()&#123; int x=0,f=1;char ch=getchar(); while (ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if (ch==&#x27;-&#x27;) f=-1;ch=getchar();&#125; while (ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=x*10+ch-48;ch=getchar();&#125; return x*f;&#125;double dist(int i,int j)&#123; return (double)sqrt((double)(x[i]-x[j])*(x[i]-x[j])+(double)(y[i]-y[j])*(y[i]-y[j]));&#125;bool cmp(int i,int j)&#123; if(x[i]==x[j]) return y[i]&lt;y[j]; return x[i]&lt;x[j];&#125;int main()&#123; n=read(); for(int i=1;i&lt;=n;i++) x[i]=read(),y[i]=read(),per[i]=i; double ans=99999999.9; sort(per+1,per+1+n,cmp); for(int i=1;i&lt;=n;i++) &#123; for(int j=i+1;j&lt;=i+6;j++) ans=min(ans,dist(per[i],per[j])); &#125; printf(&quot;%.4lf
&quot;,ans); return 0;&#125;

【全程NOIP计划】初级数据结构2 树状数组 可以用于维护前缀信息（可合并） 优点：代码段，速度快 比如： 给定一个长n的数组，支持操作： 1.将第iii个数aia_iai​加vvv 2.询问区间[l,r][l,r][l,r]中的数的和 lowbit(i)lowbit(i)lowbit(i)：只保留iii的二进制表示中最低位的1 树状数组中，节点iii表示的区间为[i−lowbit(i)+1,i][i-lowbit(i)+1,i][i−lowbit(i)+1,i] 前缀查询 查询区间[1,i][1,i][1,i]的和的时候，由iii可以直接得到[i−lowbit(i)+1,i][i-lowbit(i)+1,i][i−lowbit(i)+1,i]的和，接下来查询[1,i−lowbit(i)][1,i-lowbit(i)][1,i−lowbit(i)]的区间和，重复上面的步骤就可以了 单点修改 修改iii的时候，寻找包含i的所有区间： 第一个包含iii且lowbitlowbitlowbit比iii大的节点是i+lowbit(i)i+lowbit(i)i+lowbit(i) int lowbit(int x)&#123; return x&amp;(-x);&#125;void add(int x,int y)&#123; for( ;x&lt;=n;x+=lowbit(x)) c[x]+=y;&#125;int ask(int x)&#123; int res=0; for( ;x;x-=lowbit(x)) res+=c[x]; return res;&#125; 差分 实际上就是用树状数组维护一下差分序列的前缀和就行 区间修改 将区间[l,r][l,r][l,r]内的数全加v，或者查询[l,r][l,r][l,r]内数的和 考虑用差分数组来表示[1,R][1,R][1,R]的前缀和 ∑k=1Rak=∑k=1R∑i=1kdi=∑i=1R∑k=iRdi=∑i=1R(R−i+1)di=(R+1)∑i=1Rdi−∑i=1Ridi \sum_{k=1}^Ra_k=\sum_{k=1}^R \sum_{i=1}^kd_i \ =\sum_{i=1}^R \sum_{k=i}^Rd_i \ =\sum_{i=1}^R(R-i+1)d_i=(R+1)\sum_{i=1}^Rd_i-\sum_{i=1}^Rid_i ∑k=1R​ak​=∑k=1R​∑i=1k​di​=∑i=1R​∑k=iR​di​=∑i=1R​(R−i+1)di​=(R+1)∑i=1R​di​−∑i=1R​idi​ 逆序对 题目 给定序列，求有多少对逆序对 思路 对于每个i，它的前面有多少个数比它大 先离散化，对值域建树状数组 然后从左往右扫描一次，在每个位置需要查询权值的前缀和，然后把这个数加入树状数组 时间复杂度O(nlogn)O(nlogn)O(nlogn)
二维树状数组 给定n*m的矩阵ai,ja_{i,j}ai,j​,有qqq次操作，每次操作修改某个元素或者查询某个子矩阵的和 记录bi,jb_{i,j}bi,j​表示从(i−lowbit(i)+1,j−lowbit(j)+1)(i-lowbit(i)+1,j-lowbit(j)+1)(i−lowbit(i)+1,j−lowbit(j)+1)到(i,j)(i,j)(i,j)的子矩阵的和 查询和修改的时候，先枚举第一维，再枚举第二维 时间复杂度O(Qlogn logm)O(Qlogn \space logm)O(Qlogn logm) void update(int x,int y,int z)&#123; for(int i=x;i&lt;=n;i+=lowbit(i)) &#123; for(int j=y;j&lt;=m;j+=lowbit(j)) b[i][j]+=z; &#125;&#125;int query(int x,int y)&#123; int res=0; for(int i=x;i&gt;0;i-=lowbit(i)) &#123; for(int j=y;j&gt;0;j-=lowbit(j)) res+=b[i][j]; &#125; return res;&#125; 线段树 可以用于维护区间信息 比如： 维护长为n的序列： 包括单点修改，区间查询等操作 线段树的形式是一颗二叉树，每个节点维护一段区间的信息 根节点为[1,n][1,n][1,n] 对于节点[L,R][L,R][L,R]，设中点mid=⌊L+R2⌋mid=\lfloor \dfrac {L+R} 2 floormid=⌊2L+R​⌋,把该节点从mid处分开，左边的子节点为[L,mid][L,mid][L,mid]，右边的子节点为[mid+1,R][mid+1,R][mid+1,R] 树高O(logn)O(log n)O(logn)，总结点数2n-1 对于节点x。左儿子为2x,右儿子则为2x-1 建树 根节点为[1,n][1,n][1,n]，考虑根节点为[L,R][L,R][L,R]的时候： 设mid=(l+r)/2，对于区间[L,mid],[mid+1,R][L,mid],[mid+1,R][L,mid],[mid+1,R]递归建树 合并两个区间的信息 int a[N], mx[N &lt;&lt; 2];void update(int x, int L, int R) &#123; if(L != R) &#123; mx[x] = max(mx[x &lt;&lt; 1], mx[x &lt;&lt; 1 | 1]); &#125;&#125;void build(int x, int L, int R) &#123; if(L == R) &#123; mx[x] = a[L]; return; &#125; int mid = (L + R) &gt;&gt; 1; build(x &lt;&lt; 1, L, mid); build(x &lt;&lt; 1 | 1, mid + 1, R); update(x, L, R);&#125; 单点修改/查询 单点查询：从上向下找到对应的叶子节点 单点修改：先修改叶子节点，然后从下往上向上更新 int query(int x, int L, int R, int p) &#123; if(L == R) return mx[x]; int mid = (L + R) &gt;&gt; 1; if(p &lt;= mid) return query(x &lt;&lt; 1, L, mid, p); else return query(x &lt;&lt; 1 | 1, mid + 1, R, p);&#125;int modify(int x, int L, int R) &#123; if(L == R) &#123; mx[x] = v; return; &#125; int mid = (L + R) &gt;&gt; 1; if(p &lt;= mid) modify(x &lt;&lt; 1, L, mid, p, v); else modify(x &lt;&lt; 1 | 1, mid + 1, R, p, v); update(x, L, R);&#125; 区间查询 查询区间[l,r][l,r][l,r]的时候，可以最多拆成2log n2log \space n2log n个不相交区间，合并这些区间可以得到答案 从线段树从上往下找答案 区间修改 对区间[l,r][l,r][l,r]加vvv，同样可以拆成最多2log n2log\space n2log n个区间，并修改这些区间 在一个节点做区间修改的时候，不立刻修改它的子节点 记录懒标记：每个节点x记录还没有加到子树中的值的总和 查询经过某节点的时候，将懒标记下放给它的两个儿子 int mx[N &lt;&lt; 2], sum[N &lt;&lt; 2], tag[N &lt;&lt; 2];void update(int x) &#123; mx[x] = max(mx[x &lt;&lt; 1], mx[x &lt;&lt; 1 | 1]); sum[x] = sum[x &lt;&lt; 1] + sum[x &lt;&lt; 1 | 1];&#125;void pushdown(int x, int L, int R) &#123; if(tag[x] == 0) return; sum[x] += tag[x] * (R - L + 1); mx[x] += tag[x]; if(L != R) &#123; tag[x &lt;&lt; 1] += tag[x]; tag[x &lt;&lt; 1 | 1] += tag[x]; &#125; tag[x] = 0;&#125;// a[l...r] += vvoid modify(int x, int L, int R, int l, int r, int v) &#123; pushdown(x, L, R); if(L == l &amp;&amp; R == r) &#123; tag[x] += v; pushdown(x, L, R); return; &#125; int mid = (L + R) &gt;&gt; 1; if(r &lt;= mid) modify(x &lt;&lt; 1, L, mid, l, r, v); else if(l &gt; mid) modify(x &lt;&lt; 1 | 1, mid+1, R, l, r, v); else&#123; modify(x &lt;&lt; 1, L, mid, l, mid, v); modify(x &lt;&lt; 1 | 1, mid+1, R, mid+1, r, v); &#125; update(x);&#125; 标记永久化 // -------------- 标记永久化 ---void modify(int x, int L, int R, int l, int r, int v) &#123; if(L == l &amp;&amp; R == r) &#123; tag[x] += v; sum[x] += tag[x] * (R - L + 1); mx[x] += tag[x]; return; &#125; int mid = (L + R) &gt;&gt; 1; if(r &lt;= mid) modify(x &lt;&lt; 1, L, mid, l, r, v); else if(l &gt; mid) modify(x &lt;&lt; 1 | 1, mid+1, R, l, r, v); else&#123; modify(x &lt;&lt; 1, L, mid, l, mid, v); modify(x &lt;&lt; 1 | 1, mid+1, R, mid+1, r, v); &#125; update(x, L, R);&#125;int query(int x, int L, int R, int l, int r, int cur) &#123; if(l == L &amp;&amp; r == R) // return mx[x] + cur; return sum[x] + cur * (r - l + 1); cur += tag[x]; int mid = (L + R) &gt;&gt; 1; if(r &lt;= mid) return query(x &lt;&lt; 1, L, mid, l, r, cur); else if(l &gt; mid) return query(x &lt;&lt; 1 | 1, mid + 1, R, l, r, cur); else&#123; int u = query(x &lt;&lt; 1, L, mid, l, mid, cur); int v = query(x &lt;&lt; 1 | 1, mid + 1, R, mid + 1, r, cur); // return max(u, v); return u + v; &#125;&#125; P2023 维护序列 思路 实际上就是多一个乘法标记，跟线段树2差不多，就一板子 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=100010;int p;int a[maxn+5];struct tree&#123; int l,r; long long dat,lazy,mul;&#125;t[maxn*4+5];void pushup(int k)&#123; t[k].dat=(t[k&lt;&lt;1].dat+t[k&lt;&lt;1|1].dat)%p;&#125;void build(int k,int l,int r)&#123; t[k].lazy=0,t[k].mul=1; t[k].l=l,t[k].r=r; if(l==r) &#123; t[k].dat=a[l]; return ; &#125; int mid=(l+r)&gt;&gt;1; build(k&lt;&lt;1,l,mid); build(k&lt;&lt;1|1,mid+1,r); pushup(k);&#125;void pushdown(int k)&#123; t[k&lt;&lt;1].dat=(t[k&lt;&lt;1].dat*t[k].mul+t[k].lazy*(t[k&lt;&lt;1].r-t[k&lt;&lt;1].l+1))%p; t[k&lt;&lt;1|1].dat=(t[k&lt;&lt;1|1].dat*t[k].mul+t[k].lazy*(t[k&lt;&lt;1|1].r-t[k&lt;&lt;1|1].l+1))%p; t[k&lt;&lt;1].mul=(t[k&lt;&lt;1].mul*t[k].mul)%p; t[k&lt;&lt;1|1].mul=(t[k&lt;&lt;1|1].mul*t[k].mul)%p; t[k&lt;&lt;1].lazy=(t[k&lt;&lt;1].lazy*t[k].mul+t[k].lazy)%p; t[k&lt;&lt;1|1].lazy=(t[k&lt;&lt;1|1].lazy*t[k].mul+t[k].lazy)%p; t[k].mul=1; t[k].lazy=0;&#125;void updata(int k,int l,int r,int v)&#123; if(l&lt;=t[k].l&amp;&amp;r&gt;=t[k].r) &#123; t[k].dat=(t[k].dat+(long long)v*(t[k].r-t[k].l+1))%p; t[k].lazy=(t[k].lazy+v)%p; return ; &#125; pushdown(k); int mid=(t[k].l+t[k].r)&gt;&gt;1; if(l&lt;=mid) updata(k&lt;&lt;1,l,r,v); if(r&gt;mid) updata(k&lt;&lt;1|1,l,r,v); pushup(k);&#125;void updata2(int k,int l,int r,int v)&#123; if(l&lt;=t[k].l&amp;&amp;r&gt;=t[k].r) &#123; t[k].dat=(t[k].dat*v)%p; t[k].lazy=(t[k].lazy*v)%p; t[k].mul=(t[k].mul*v)%p; return ; &#125; pushdown(k); int mid=(t[k].l+t[k].r)&gt;&gt;1; if(l&lt;=mid) updata2(k&lt;&lt;1,l,r,v); if(r&gt;mid) updata2(k&lt;&lt;1|1,l,r,v); pushup(k);&#125;long long query(int k,int l,int r)&#123; if(l&lt;=t[k].l&amp;&amp;r&gt;=t[k].r) return t[k].dat; pushdown(k); int mid=(t[k].l+t[k].r)&gt;&gt;1; long long ans=0%p; if(l&lt;=mid) ans+=query(k&lt;&lt;1,l,r)%p; if(r&gt;mid) ans+=query(k&lt;&lt;1|1,l,r)%p; return ans%p;&#125;int main()&#123; std::ios::sync_with_stdio(false); int n,m; cin&gt;&gt;n&gt;&gt;p; for(int i=1;i&lt;=n;i++) cin&gt;&gt;a[i]; cin&gt;&gt;m; build(1,1,n); for(int i=1;i&lt;=m;i++) &#123; int o; cin&gt;&gt;o; if(o==1) &#123; int x,y,k; cin&gt;&gt;x&gt;&gt;y&gt;&gt;k; updata2(1,x,y,k); continue; &#125; if(o==2) &#123; int x,y,k; cin&gt;&gt;x&gt;&gt;y&gt;&gt;k; updata(1,x,y,k); continue; &#125; if(o==3) &#123; int x,y; cin&gt;&gt;x&gt;&gt;y; cout&lt;&lt;query(1,x,y)&lt;&lt;&#x27;
&#x27;; &#125; &#125; return 0;&#125; P4513 小白逛公园 思路 在每个节点处维护： 区间最大字段和，区间最大前缀和和区间最大后缀和 合并的时候分类讨论就好了 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=500005;int n,m;int a[maxn];struct tree&#123; int l,r; int sum,lmax,rmax,maxx;&#125;t[maxn*4];void pushup(int k)&#123; t[k].sum=t[k&lt;&lt;1].sum+t[k&lt;&lt;1|1].sum; t[k].lmax=max(t[k&lt;&lt;1].sum+t[k&lt;&lt;1|1].lmax,t[k&lt;&lt;1].lmax); t[k].rmax=max(t[k&lt;&lt;1|1].sum+t[k&lt;&lt;1].rmax,t[k&lt;&lt;1|1].rmax); t[k].maxx=max(max(t[k&lt;&lt;1].maxx,t[k&lt;&lt;1|1].maxx),t[k&lt;&lt;1].rmax+t[k&lt;&lt;1|1].lmax);&#125;void build(int k,int l,int r)&#123; t[k].l=l,t[k].r=r; if(l==r) &#123; t[k].sum=t[k].lmax=t[k].rmax=t[k].maxx=a[l]; return ; &#125; int mid=(l+r)&gt;&gt;1; build(k&lt;&lt;1,l,mid); build(k&lt;&lt;1|1,mid+1,r); pushup(k);&#125;void update(int k,int p,int v)&#123; if(t[k].l==t[k].r) &#123; t[k].sum=t[k].lmax=t[k].rmax=t[k].maxx=v; return ; &#125; int mid=(t[k].l+t[k].r)&gt;&gt;1; if(mid&gt;=p) update(k&lt;&lt;1,p,v); else update(k&lt;&lt;1|1,p,v); pushup(k);&#125;tree query(int k,int l,int r)&#123; if(l&lt;=t[k].l&amp;&amp;t[k].r&lt;=r) return t[k]; int mid=(t[k].l+t[k].r)&gt;&gt;1; if(r&lt;=mid) return query(k&lt;&lt;1,l,r); else if(l&gt;mid) return query(k&lt;&lt;1|1,l,r); else &#123; tree x=query(k&lt;&lt;1,l,r); tree y=query(k&lt;&lt;1|1,l,r); tree merge; merge.sum=x.sum+y.sum; merge.lmax=max(x.sum+y.lmax,x.lmax); merge.rmax=max(y.sum+x.rmax,y.rmax); merge.maxx=max(max(x.maxx,y.maxx),x.rmax+y.lmax); return merge; &#125;&#125;int main()&#123; cin&gt;&gt;n&gt;&gt;m; for(int i=1;i&lt;=n;i++) cin&gt;&gt;a[i]; build(1,1,n); for(int i=1;i&lt;=m;i++) &#123; int op; cin&gt;&gt;op; if(op==1) &#123; int a,b; cin&gt;&gt;a&gt;&gt;b; if(a&gt;b) swap(a,b); tree ans=query(1,a,b); cout&lt;&lt;ans.maxx&lt;&lt;&#x27;
&#x27;; &#125; else &#123; int p,s; cin&gt;&gt;p&gt;&gt;s; update(1,p,s); &#125; &#125; return 0;&#125; P2894 Hotel 思路 线段树 类似上一道题目 在每个节点处维护： 区间内最长全0的长度，最长全0前缀和最长全0后缀 查询时，在线段树上二分找到最靠前的答案 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=500005;int n,m;struct tree&#123; int sum; int len; int lmax,rmax; int lazy;&#125;t[maxn*4];void pushup(int k)&#123; if(t[k&lt;&lt;1].sum==t[k&lt;&lt;1].len) t[k].lmax=t[k&lt;&lt;1].len+t[k&lt;&lt;1|1].lmax; else t[k].lmax=t[k&lt;&lt;1].lmax; if(t[k&lt;&lt;1|1].sum==t[k&lt;&lt;1|1].len) t[k].rmax=t[k&lt;&lt;1|1].len+t[k&lt;&lt;1].rmax; else t[k].rmax=t[k&lt;&lt;1|1].rmax; t[k].sum=max(max(t[k&lt;&lt;1].sum,t[k&lt;&lt;1|1].sum),t[k&lt;&lt;1].rmax+t[k&lt;&lt;1|1].lmax);&#125; void pushdown(int k)&#123; if(t[k].lazy==0) return; if(t[k].lazy==1) &#123; t[k&lt;&lt;1].lazy=t[k&lt;&lt;1|1].lazy=1; t[k&lt;&lt;1].sum=t[k&lt;&lt;1].lmax=t[k&lt;&lt;1].rmax=0; t[k&lt;&lt;1|1].sum=t[k&lt;&lt;1|1].lmax=t[k&lt;&lt;1|1].rmax=0; &#125; if(t[k].lazy==2) &#123; t[k&lt;&lt;1].lazy=t[k&lt;&lt;1|1].lazy=2; t[k&lt;&lt;1].sum=t[k&lt;&lt;1].lmax=t[k&lt;&lt;1].rmax=t[k&lt;&lt;1].len; t[k&lt;&lt;1|1].sum=t[k&lt;&lt;1|1].lmax=t[k&lt;&lt;1|1].rmax=t[k&lt;&lt;1|1].len; &#125; t[k].lazy=0;&#125;void build(int k,int l,int r)&#123; t[k].lazy=0; t[k].sum=t[k].len=t[k].lmax=t[k].rmax=r-l+1; if(l==r) return; int mid=(l+r)/2; build(k&lt;&lt;1,l,mid); build(k&lt;&lt;1|1,mid+1,r); &#125;void update(int k,int l,int r,int tag,int L,int R)&#123; pushdown(k); if(L&lt;=l&amp;&amp;r&lt;=R) &#123; if(tag==1)t[k].sum=t[k].lmax=t[k].rmax=0; else t[k].sum=t[k].lmax=t[k].rmax=t[k].len; t[k].lazy=tag; return; &#125; int mid=(l+r)/2; if(L&lt;=mid) update(k&lt;&lt;1,l,mid,tag,L,R); if(R&gt;mid) update(k&lt;&lt;1|1,mid+1,r,tag,L,R); pushup(k);&#125;int query(int k,int l,int r,int length)&#123; pushdown(k); if(l==r)return l; int mid=(l+r)/2; if(t[k&lt;&lt;1].sum&gt;=length) return query(k&lt;&lt;1,l,mid,length); if(t[k&lt;&lt;1].rmax+t[k&lt;&lt;1|1].lmax&gt;=length) return mid-t[k&lt;&lt;1].rmax+1; else return query(k&lt;&lt;1|1,mid+1,r,length);&#125;int main()&#123; cin&gt;&gt;n&gt;&gt;m; build(1,1,n); for(int i=1;i&lt;=m;i++) &#123; int op,x,y; cin&gt;&gt;op; if(op==1) &#123; cin&gt;&gt;x; if(t[1].sum&gt;=x) &#123; int l=query(1,1,n,x); cout&lt;&lt;l&lt;&lt;&#x27;
&#x27;; update(1,1,n,1,l,l+x-1); &#125; else cout&lt;&lt;0&lt;&lt;&#x27;
&#x27;; &#125; else &#123; cin&gt;&gt;x&gt;&gt;y; update(1,1,n,2,x,x+y-1); &#125; &#125; return 0;&#125; P5490 扫描线 思路 一个扫描线的模板 离散化坐标，并按照x从小到大的顺序扫描 每一步加入或者删除一个矩形（一根线段），线段树维护被覆盖部分 维护被覆盖的面基，节点记录： 实际区间长度，被覆盖部分长度，最小值，最小值部分长度 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;string&gt;#include &lt;cstring&gt;using namespace std;const int maxn=1e6+5;int n;long long x1,y1,x2,y2;long long x[maxn*2];struct scanline&#123; long long l,r,h; int mark; bool operator &lt; (const scanline &amp;rhs) const &#123; return h&lt;rhs.h; &#125;&#125;line[maxn*2];struct tree&#123; int l,r; int sum; long long len;&#125;t[maxn*4];void pushup(int k)&#123; if(t[k].sum) t[k].len=x[t[k].r+1]-x[t[k].l]; else t[k].len=t[k&lt;&lt;1].len+t[k&lt;&lt;1|1].len;&#125;void build(int k,int l,int r)&#123; t[k].l=l,t[k].r=r; t[k].len=0; t[k].sum=0; if(l==r) return ; int mid=(l+r)&gt;&gt;1; build(k&lt;&lt;1,l,mid); build(k&lt;&lt;1|1,mid+1,r);&#125;void edit_tree(int k,long long l,long long r,int c)&#123; if(x[t[k].r+1]&lt;=l||r&lt;=x[t[k].l]) return ; if(l&lt;=x[t[k].l]&amp;&amp;x[t[k].r+1]&lt;=r) &#123; t[k].sum+=c; pushup(k); return ; &#125; edit_tree(k&lt;&lt;1,l,r,c); edit_tree(k&lt;&lt;1|1,l,r,c); pushup(k);&#125;int main()&#123; cin&gt;&gt;n; for(int i=1;i&lt;=n;i++) &#123; cin&gt;&gt;x1&gt;&gt;y1&gt;&gt;x2&gt;&gt;y2; x[2*i-1]=x1,x[2*i]=x2; line[2*i-1]=(scanline)&#123;x1,x2,y1,1&#125;; line[2*i]=(scanline)&#123;x1,x2,y2,-1&#125;; &#125; n&lt;&lt;=1; sort(line+1,line+1+n); sort(x+1,x+1+n); //离散化 int tot=unique(x+1,x+1+n)-x-1; build(1,1,tot-1); long long ans=0; for(int i=1;i&lt;n;i++) &#123; edit_tree(1,line[i].l,line[i].r,line[i].mark); ans+=t[1].len*(line[i+1].h-line[i].h); &#125; cout&lt;&lt;ans&lt;&lt;endl; return 0;&#125; 线段树的可持久化 可持久化：支持保存和访问数据结构历史版本 可持久化线段树 在单次修改之后，产生变化的节点只有O(log n)O(log \space n)O(log n)个 只需要为这些节点开辟新的空间 不能用堆式编号，需要记录子树节点编号，并动态开点，区间操作需要标记永久化，单次操作的时间和空间复杂度为O(log n)O(log \space n)O(log n) const int maxn=100005;struct node&#123; int l,r; int sum,ls,rs;&#125;a[20*maxn];int cnt,root[maxn];//root代表每次操作之后的根节点void modify(int &amp;x,int L,int R,int p,int v)//把p位置修改成v&#123; if(!x) x=++cnt;//如果x还没有开，那就新开一个点 if(L==R) &#123; a[x].sum=v; return ; &#125; int mid=(L+R)&gt;&gt;1; if(p&lt;=mid) modify(a[x].ls,L,mid,p,v); else modify(a[x].rs,mid+1,R,p,v); a[x].sum=a[a[x].ls].sum+a[a[x].rs].sum;//合并信息&#125;int query(int x,int L,int R,int l,int r)&#123; if(x==0) return 0; if(l==L&amp;&amp;r==R) return a[x].sum; int mid=(L+R)&gt;&gt;1; if(r&lt;=mid) return query(a[x].ls,L,mid,l,r); else if(l&gt;mid) return query(a[x].rs,mid+1,R,l,r); else &#123; int u=query(a[x].ls,L,mid,l,mid); int v=query(a[x].rs,mid+1,R,mid+1,r); return u+v; &#125;&#125;int main() &#123; for(int i=1; i&lt;=Q; i++) &#123; root[i] = root[i-1]; modify(root[i], 1, n, p, v); &#125; return 0;&#125; 可持久化并查集 用持久化也可以实现可持久化并查集 P3834 可持久化线段树（模板） 思路 考虑区间是[1,n][1,n][1,n]的情况： 1.离散化之后建立值域线段树，区间[L,R][L,R][L,R]保存落在[L,R][L,R][L,R]内的数的个数 2.在线段树上二分找到第k大的值 3.如果左子树的总和≤k\le k≤k，则向左子树走，否则向右子树走
主席树 区间[L,R][L,R][L,R]的值域线段树，可以用[1,R],[1,L−1][1,R],[1,L-1][1,R],[1,L−1]的相减得到 暴力：开n棵线段树，时间复杂度为O(n2)O(n^2)O(n2) 1.将第i棵线段树在第i-1棵线段树的基础上修改了一个值 2.将线段树可持久化，一共n个版本,查询时同时访问两个历史版本，并把他们相减 int query_kth(int x,int L,int R,int k)&#123; if(L==R) return L; int mid=(L+R)&gt;&gt;1; int =a[a[x].ls].sum-a[a[y].ls].sum; if(s&gt;=k) return query(a[x].ls,L,mid,k); else return query(a[x].rc,mid+1,R,k-s);&#125;//其他的const int N = 100005;struct Node&#123; int lc, rc, sum;&#125;a[20 * N];int cnt, root[N];// a[p] = v;void modify(int&amp; x, int L, int R, int p, int v) &#123; a[++cnt] = a[x]; x = cnt; if(L == R) &#123; a[x].sum = v; return; &#125; int mid = (L + R) &gt;&gt; 1; if(p &lt;= mid) modify(a[x].lc, L, mid, p, v); else modify(a[x].rc, mid+1, R, p, v); a[x].sum = a[a[x].lc].sum + a[a[x].rc].sum; // a[0].sum = 0;&#125;int query(int x, int L, int R, int l, int r) &#123; if(x == 0) return 0; if(l == L &amp;&amp; r == R) return a[x].sum; int mid = (L + R) &gt;&gt; 1; if(r &lt;= mid) return query(a[x].lc, L, mid, l, r); else if(l &gt; mid) return query(a[x].rc, mid + 1, R, l, r); else&#123; int u = query(a[x].lc, L, mid, l, mid); int v = query(a[x].rc, mid + 1, R, mid + 1, r); return u + v; &#125;&#125;int main() &#123; for(int i=1; i&lt;=Q; i++) &#123; root[i] = root[i-1]; modify(root[i], 1, n, p, v); // root[i] = ++cnt &#125; // query(root[i], 1, n, l, r); return 0;&#125; P4216 情报传递 思路 得到一个路径的主席树 综合练习 P4145 花神游历各国 思路 注意到每个数最多开根6次后就会变成1 方法1： 在线段树上暴力开根，把全都是1的区间打上标记 方法2： 树状数组暴力单点修改，在修改的时候跳过所有的1，可以使用并查集来实现 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;cmath&gt;using namespace std;const int maxn=100005;long long n,m;long long a[maxn],b[maxn];bool vis[maxn]=&#123;false&#125;;long long fa[maxn];long long get(long long x)&#123; return fa[x]=(x==fa[x]? x:get(fa[x]));&#125;void init()&#123; for(int i=1;i&lt;=maxn-5;i++) fa[i]=i;&#125;inline long long read()&#123; long long x=0,f=1;char ch=getchar(); while (ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if (ch==&#x27;-&#x27;) f=-1;ch=getchar();&#125; while (ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=x*10+ch-48;ch=getchar();&#125; return x*f;&#125;long long lowbit(long long x)&#123; return x&amp;(-x);&#125;void add(long long x,long long y)&#123; for( ;x&lt;=n;x+=lowbit(x)) b[x]+=y; &#125;long long ask(long long x)&#123; long long res=0; for( ;x;x-=lowbit(x)) res+=b[x]; return res;&#125;int main()&#123; init(); n=read(); for(register long long i=1;i&lt;=n;i++) &#123; a[i]=read(); add(i,a[i]); &#125; fa[n+1]=n+1; m=read(); while(m--) &#123; int k=read(),l=read(),r=read(); if(l&gt;r) swap(l,r); if(k==0) &#123; long long t; for(int i=l;i&lt;=r;add(i,(t=(int)sqrt(a[i]))-a[i]),a[i]=t,fa[i]=(a[i]&lt;=1)?i+1:i,i=(get(i)==i)?i+1:fa[i]); &#125; else &#123; cout&lt;&lt;ask(r)-ask(l-1)&lt;&lt;&#x27;
&#x27;; &#125; &#125; return 0;&#125; P1972 HH的项链 思路 离线询问，从左往右考虑每个下标iii，并处理右端点iii的询问 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=1000005;int n,m;int a[maxn],b[maxn];int vis[maxn],ans[maxn];struct qyj&#123; int l,r; int id;&#125;q[maxn];int lowbit(int x)&#123; return x&amp;(-x);&#125;void add(int x,int y)&#123; for( ;x&lt;=n;x+=lowbit(x)) b[x]+=y;&#125;int ask(int x)&#123; int res=0; for( ;x; x-=lowbit(x)) res+=b[x]; return res;&#125;bool cmp(qyj x,qyj y)&#123; return x.r&lt;y.r; &#125;int main()&#123; cin&gt;&gt;n; for(int i=1;i&lt;=n;i++) cin&gt;&gt;a[i]; cin&gt;&gt;m; for(int i=1;i&lt;=m;i++) &#123; cin&gt;&gt;q[i].l&gt;&gt;q[i].r; q[i].id=i; &#125; sort(q+1,q+1+m,cmp); int pow=1; for(int i=1;i&lt;=m;i++) &#123; for(int j=pow;j&lt;=q[i].r;j++) &#123; if(vis[a[j]]) add(vis[a[j]],-1); add(j,1); vis[a[j]]=j; &#125; pow=q[i].r+1; ans[q[i].id]=ask(q[i].r)-ask(q[i].l-1); &#125; for(int i=1;i&lt;=m;i++) cout&lt;&lt;ans[i]&lt;&lt;&#x27;
&#x27;; return 0;&#125; P4587 神秘数 思路 如果没有区间查询： 从小到大考虑每一个数，设当前能表示出[1,x][1,x][1,x]的数 如果下一个数ai≥x+2a_i \ge x+2ai​≥x+2，则答案是x+1x+1x+1 否则，能表示的数的范围则扩充到[1,x+ai][1,x+a_i][1,x+ai​] 优化扩充的过程：设一个last，表示用≤last\le last≤last的数凑出的范围是[1,x][1,x][1,x] 如果下一个数&gt;x+1&gt;x+1&gt;x+1,则答案就是x+1x+1x+1 否则，求出所有在[last+1,x][last+1,x][last+1,x]之间的数的和sumsumsum 则xxx增加到x+sumx+sumx+sum，lastlastlast增加到原来的xxx 扩充不超过O(log(∑ai))O(log(\sum a_i))O(log(∑ai​))步（斐波那契） 然后主席树实现查询 总的时间复杂度为O(mlog n log(∑ai))O(mlog \space n \space log(\sum a_i))O(mlog n log(∑ai​)) P1712 区间 思路 按照区间长度排序，双指针扫一遍 线段树区间加，维护区间最大值 时间复杂度O(nlogn)O(nlogn)O(nlogn)

【全程NOIP计划】动态规划及优化1 LIS 非常经典，最长上升子序列 设计状态 以f[x]f[x]f[x]表示序列a中以axa_xax​结尾的LIS长度 涉及转移 f[x]=maxi&lt;x,ai≤ax(f[i]+1)f[x]=max_{i&lt;x,a_i\le a_x}(f[i]+1)f[x]=maxi&lt;x,ai​≤ax​​(f[i]+1) DP的状态和转移 一个问题可以DP，是因为这个问题可以从小问题的解推出大问题的解 我们可以从初始状态的解，推出最终状态的解，从而解决问题 本质 首先我们把LIS的问题中的每个状态作为点，放在图上 我们知道f[1]=1f[1]=1f[1]=1，因为单个字符的LIS长度只有1，现在想知道f[4]f[4]f[4]，这就需要转移来实现 如果状态x可以直接抵达y状态，我们就连上x→yx ightarrow yx→y的有向边 如果我们按照上面的方式画图，我们就可以发现几个性质 1.DP的每一个状态对应着一个点 2.每种可能的转移方式，都对应着一条有向边 3.DP的求解顺序，等同于这张图的拓扑排序 4.必须是有向无环图DAG，否则无法找到合适的求解顺序 两种转移方式 DP有两种转移方法： 1.pull型，主要考察一个状态如何从其他状态推出结果 2.push型，主要考察一个状态得到解之后，如何去更新其他的状态 本质上对应着自顶向下的拓扑排序和自下向顶的拓扑排序 计数类DP实质上不是DP，但是和DP很像，所以我们也叫它DP P1002 过河卒 思路 f[x][y]f[x][y]f[x][y]表示抵达(x,y)(x,y)(x,y)的方案数量 可以很快找到转移 f[x][y]={0,marked[x][y]f[x][y−1]+f[x−1][y],otherwise f[x][y]= egin{cases}0, &amp;	ext{marked[x][y]} \ f[x][y-1]+f[x-1][y],&amp;	ext{otherwise} \end{cases} f[x][y]={0,f[x][y−1]+f[x−1][y],​marked[x][y]otherwise​ 然后加上滚动数组可以找到转移 f[x][y]={0,marked[x][y]f[x]+f[x−1],otherwise f[x][y]= egin{cases}0, &amp;	ext{marked[x][y]} \ f[x]+f[x-1],&amp;	ext{otherwise} \end{cases} f[x][y]={0,f[x]+f[x−1],​marked[x][y]otherwise​ 注意循环的顺序，如果我们从小到大枚举xxx，则本层的xxx会更新本层的x+1x+1x+1，本层的x+1x+1x+1会更新本层的$x+2 \dots $，事实上本层的值应该由上一层来确定 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;using namespace std;int fx[]=&#123;0,-2,-1,1,2,2,1,-1,-2&#125;;int fy[]=&#123;0,1,2,2,1,-1,-2,-2,-1&#125;;int bx,by,mx,my;long long f[30][30];bool s[30][30];int main()&#123; cin&gt;&gt;bx&gt;&gt;by&gt;&gt;mx&gt;&gt;my; bx+=1,by+=1,mx+=1,my+=1; f[1][1]=1; s[mx][my]=1; for(int i=1;i&lt;=8;i++) s[mx+fx[i]][my+fy[i]]=1; for(int i=1;i&lt;=bx;i++) &#123; for(int j=1;j&lt;=by;j++) &#123; if(s[i][j]) continue; f[i][j]=max(f[i][j],f[i-1][j]+f[i][j-1]); &#125; &#125; cout&lt;&lt;f[bx][by]&lt;&lt;endl; return 0;&#125; 滚动数组技巧 一个DP可以通过滚动数组来优化，当且仅当其状态图是分层的，下k层的结果由上d层的结果唯一确定 单层滚动数组的通用写法 开两个数组arroldarr_{old}arrold​,arrnewarr_{new}arrnew​，分别保存旧层和新层，通过旧层计算出新层的值，然后覆盖掉旧层 覆盖可以通过memcpy或者交换指针实现。 通用写法的优势：无需考虑特殊的求值顺序 关于记忆化搜索 只需要直接实现pull型转移，无需在代码中考虑循环顺序 只经历可能达到的状态，不会经过无效的区间状态，节省时间 所以我们很多时候是喜欢记忆化搜索的，尤其是区间DP问题 写法上，我们判断是否记忆可以采用vis数组，如果DP结果可能是0，一定要把初值设为其他值 DAG最短路 题目 有一个DAG，给定一个S，和一个T，求S到T之间的最短距离 思路 用f(x)f(x)f(x)表示从起点到x的距离 那么显然有 f[x]=min(f[u]+dis[u][x])f[x]=min(f[u]+dis[u][x])f[x]=min(f[u]+dis[u][x]) 那我们能不能推广到任意图的最短路呢? 显然不行，因为如果有环的话会出现一个循环依赖问题 主要是因为产生了后效性 所以换一种设计状态方法： 设f[k][x]f[k][x]f[k][x]为从起点开始，经历不超过k个点，到达x的最短路径长度 我们一举解决了循环依赖问题，f[k][x]f[k][x]f[k][x]只会依赖于f[k−1][.]f[k-1][.]f[k−1][.] 状态转移如下 f[k][x]=min(f[k−1][u]+dis[u][x])f[k][x]=min(f[k-1][u]+dis[u][x])f[k][x]=min(f[k−1][u]+dis[u][x]) 注意到这个是分层的，滚动数组优化之后，就是Bellman−FordBellman-FordBellman−Ford单源最短路算法 用DP看Floyd 我们刚刚解决了单源最短路径问题，现在要求出图中任意两点间的距离，那我们如何DP呢？ 第一时间想到f[u][v]f[u][v]f[u][v]表示u到v的距离，但由于循环依赖问题，没有合适的转移 于是考虑记录f[k][u][v]f[k][u][v]f[k][u][v]表示从u开始经历不超过k个点到达v的最短路 显然有f[k][u][v]=min(f[k−1][u][x]+dis[x][v])f[k][u][v]=min(f[k-1][u][x]+dis[x][v])f[k][u][v]=min(f[k−1][u][x]+dis[x][v]) 因为是分层的，滚动数组滚掉第一维，我们就可以得到了FloydFloydFloyd算法 P1018 乘积最大 思路 用f[pos][d]f[pos][d]f[pos][d]表示把数字串的[0,pos)[0,pos)[0,pos)位划分为ddd段，得到的收益。则转移是显然的 f[pos][d]=maxx&lt;pos(f[x][d−1]∗a[x,pos)) f[pos][d]=max_{x&lt;pos}(f[x][d-1]*a_{[x,pos)}) f[pos][d]=maxx&lt;pos​(f[x][d−1]∗a[x,pos)​) 技巧： 1.处理序列问题的时候，往往考虑将此序列的前缀作为子问题 2.处理字符串的时候采用左闭右开区间，常常可以省代码 没加高精度60分，高精度不想写来着 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#define int long longusing namespace std;const int maxn=55;int n,k;int v[maxn];char s[maxn];int a[maxn][maxn];int f[maxn][maxn];signed main()&#123; cin&gt;&gt;n&gt;&gt;k; for(int i=1;i&lt;=n;i++) &#123; char c; cin&gt;&gt;c; v[i]=c-&#x27;0&#x27;; &#125; for(int i=1;i&lt;=n;i++) &#123; for(int j=i;j&lt;=n;j++) a[i][j]=(a[i][j-1]*10+v[j]); &#125; for(int i=1;i&lt;=n;i++) f[i][0]=a[1][i]; for(int pos=1;pos&lt;=n;pos++) &#123; for(int d=1;d&lt;=k;d++) &#123; for(int x=1;x&lt;pos;x++) f[pos][d]=max(f[pos][d],f[x][d-1]*a[x+1][pos]); &#125; &#125; cout&lt;&lt;f[n][k]&lt;&lt;&#x27;
&#x27;; return 0;&#125; CF1061C Multiplicity 题目 从序列 {a1, a2, .. , an}\{a_1,\ a_2,\ ..\ ,\ a_n\}{a1​, a2​, .. , an​} 中选出非空子序列 {b1, b2, .. , bk}\{b_1,\ b_2,\ ..\ ,\ b_k\}{b1​, b2​, .. , bk​}，一个子序列合法需要满足 ∀ i∈[1, k], i ∣ bi orall\ i \in [1,\ k],\ i\ |\ b_i∀ i∈[1, k], i ∣ bi​。求有多少互不相等的合法子序列，答案对 109+710^9 + 7109+7 取模。 序列 {1, 1}\{1,\ 1\}{1, 1} 有 222 种选法得到子序列 {1}\{1\}{1}，但 111 的来源不同，认为这两个子序列不相等。 思路 f[x][k]f[x][k]f[x][k]表示从序列的前x位选k个的方案数 f[x][k]f[x][k]f[x][k]从哪里来？ 第x位要不要选做子序列的第k个？ 则有f[x−1][k]f[x-1][k]f[x−1][k]和,f[x−1][k−1]f[x-1][k-1]f[x−1][k−1]中转移过来 那么我们就有 f[x][y]={f[x−1][y]+f[x−1][y−1],y∣a[i]f[x−1][y]otherwise f[x][y]=  egin{cases} f[x-1][y]+f[x-1][y-1],&amp;y|a[i] \ f[x-1][y] &amp;otherwise \end{cases} f[x][y]={f[x−1][y]+f[x−1][y−1],f[x−1][y]​y∣a[i]otherwise​ 发现xxx由x−1x-1x−1唯一确定 可以加一个滚动数组优化 于是代码框架是：外层枚举x，内层枚举y进行转移 现在来优化时间，考虑内层循环的次数，我们知道，只有当y∣a[x]y|a[x]y∣a[x]的那些y才需要特殊考虑，于是因数分解a[x]a[x]a[x] 总的复杂度O(nn)O(n\sqrt{n})O(nn​) #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;string&gt;#include &lt;cstring&gt;#include &lt;vector&gt;using namespace std;const int mod=1e9+7;const int maxn=100005;int n;int a[maxn];int f[maxn];vector &lt;int&gt; fac;void get_factor(int x)&#123; for(int i=1;i*i&lt;=x;i++) &#123; if(x%i==0) &#123; fac.push_back(i); if(x!=i*i) fac.push_back(x/i); &#125; &#125; sort(fac.begin(),fac.end(),greater&lt;int&gt;());&#125;int main()&#123; cin&gt;&gt;n; for(int i=1;i&lt;=n;i++) cin&gt;&gt;a[i]; f[0]=1; for(int i=1;i&lt;=n;i++) &#123; get_factor(a[i]); for(auto j:fac) &#123; if(j&lt;=i) f[j]=(f[j]+f[j-1])%mod; &#125; fac.clear(); &#125; int ans=0; for(int i=1;i&lt;=n;i++) ans=(ans+f[i])%mod; cout&lt;&lt;ans&lt;&lt;&#x27;
&#x27;; return 0;&#125; P1004 方格取数 思路 两个人同时走和先后走是一样的结果，只要保证每个数只被取到一次 设计f[step][a][b][x][y]f[step][a][b][x][y]f[step][a][b][x][y]表示两个人各走stepstepstep步，第一个人走到(a,b)(a,b)(a,b)，第二个人走到(x,y)(x,y)(x,y)能获取的最大价值 有 f[step][a][b][x][y]=benifit+max{f[step−1][a−1][b][x−1][y]f[step−1][a−1][b][x][y−1]f[step−1][a][b−1][x−1][y]f[step−1][a][b−1][x][y−1] f[step][a][b][x][y]=benifit+max  egin{cases} f[step-1][a-1][b][x-1][y] \ f[step-1][a-1][b][x][y-1] \ f[step-1][a][b-1][x-1][y] \ f[step-1][a][b-1][x][y-1] \ \end{cases} f[step][a][b][x][y]=benifit+max⎩⎪⎪⎪⎪⎨⎪⎪⎪⎪⎧​f[step−1][a−1][b][x−1][y]f[step−1][a−1][b][x][y−1]f[step−1][a][b−1][x−1][y]f[step−1][a][b−1][x][y−1]​ 然后发现根据滚动数组，可以stepstepstep这一层滚掉，不难写出代码 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;string&gt;#include &lt;cstring&gt;using namespace std;const int N=15;int n;int w[N][N];int f[N*2][N][N];int main()&#123; memset(w,0,sizeof(w)); cin&gt;&gt;n; while(1) &#123; int x,y,z; cin&gt;&gt;x&gt;&gt;y&gt;&gt;z; if(x==0&amp;&amp;y==0&amp;&amp;z==0) break; w[x][y]=z; &#125; memset(f,0,sizeof(f)); for(int k=2;k&lt;=n+n;k++) &#123; for(int x1=max(1,k-n);x1&lt;=min(k-1,n);x1++) &#123; for(int x2=max(1,k-n);x2&lt;=min(k-1,n);x2++) &#123; int t=w[x1][k-x1]; if(x1!=x2) t+=w[x2][k-x2]; for(int a=0;a&lt;=1;a++) &#123; for(int b=0;b&lt;=1;b++) f[k][x1][x2]=max(f[k][x1][x2],f[k-1][x1-a][x2-b]+t); &#125; &#125; &#125; &#125; cout&lt;&lt;f[2*n][n][n]&lt;&lt;endl; return 0; &#125; CF245H Queries for Number of Palindromes 思路 题意就是要统计l到r内的回文子串的个数 设答案为f[l][r]f[l][r]f[l][r],根据容斥原理 f[l][r]=f[l][r−1]+f[l+1][r]−f[l+1][r−1]+ispal(sl…r) f[l][r]=f[l][r-1]+f[l+1][r]-f[l+1][r-1]+ispal(s_{l\dots r}) f[l][r]=f[l][r−1]+f[l+1][r]−f[l+1][r−1]+ispal(sl…r​) 其中is_pal可以O(∣s∣2)O(|s|^2)O(∣s∣2)预处理 所以整个问题可以在O(∣s∣2)O(|s|^2)O(∣s∣2)的时间内解决 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;string&gt;#include &lt;cstring&gt;using namespace std;const int maxn=5005;char s[maxn];bool is_pal[maxn][maxn];bool visit_pal[maxn][maxn];inline int read()&#123; int x=0,f=1;char ch=getchar(); while (ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if (ch==&#x27;-&#x27;) f=-1;ch=getchar();&#125; while (ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=x*10+ch-48;ch=getchar();&#125; return x*f;&#125;void get_is_pal(int l,int r)&#123; if(visit_pal[l][r]) return; if(l==r||r==l+1) &#123; is_pal[l][r]=(s[l]==s[r]); return; &#125; get_is_pal(l+1,r-1); if(is_pal[l+1][r-1]) is_pal[l][r]=(s[l]==s[r]); visit_pal[l][r]=true;&#125;int f[maxn][maxn];bool visit_dp[maxn][maxn];void get_dp(int l,int r) &#123; if(visit_dp[l][r]) return; if(l==r) &#123; f[l][r]=1; return; &#125; if(r==l+1) &#123; f[l][r]=2+is_pal[l][r]; return; &#125; get_dp(l,r-1); get_dp(l+1,r); get_dp(l+1,r-1); f[l][r]=f[l][r-1]+f[l+1][r]-f[l+1][r-1]+is_pal[l][r]; visit_dp[l][r]=true;&#125;int main()&#123; scanf(&quot;%s&quot;,s+1); int len=strlen(s+1); for(int x=1;x&lt;=len;x++) for(int y=x;y&lt;=len;y++) get_is_pal(x,y); for(int x=1;x&lt;=len;x++) for(int y=x;y&lt;=len;y++) get_dp(x,y); int T=read(); while(T--) &#123; cout&lt;&lt;f[read()][read()]&lt;&lt;&#x27;
&#x27;; &#125; return 0;&#125; P1385 密令 思路 首先发现一条性质：我们设字符串的总和为sum，则任何字母总和为sum的等长的串都是可以达到的。 证明： 采用构造方法，我们从前往后构造新的字符串，考虑第一个字符，如果比目标大就用(−1,+1)(-1,+1)(−1,+1)变换，比目标小就用(+1,−1)(+1,-1)(+1,−1)变换，然后去搞第二个字符……一次类推，直到搞完前n−1n-1n−1位 至于最后一位，我们断言它此时必定等于目标串的最后一位，这是因为两种变换均不会改变字母和sumsumsum 于是整个问题就简化为： 给定sumsumsum，有多少种长度为nnn的序列满足： 1.每个元素在[1,26][1,26][1,26]之间 2.序列和为sumsumsum 然后就开始DP，设f[k][x]f[k][x]f[k][x]表示长度为kkk的序列之和为xxx的方案数量，答案显然是f[n][sum]f[n][sum]f[n][sum],然后转移就是显然的 f[k][x]=∑1≤i≤min(26,x)f[k−1][x−i] f[k][x]=\sum_{1 \le i \le min(26,x)}f[k-1][x-i] f[k][x]=∑1≤i≤min(26,x)​f[k−1][x−i] 注意最后要减去原先的那一个 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#define int long longusing namespace std;const int mod=1e9+7;int T;char s[105];int f[105][5005];signed main()&#123; cin&gt;&gt;T; for(int i=0;i&lt;26;i++) f[1][i]=1; for(int i=1;i&lt;=100;i++) f[i][0]=1; for(int k=2;k&lt;=100;k++) &#123; for(int x=1;x&lt;=2500;x++) &#123; for(int i=0;i&lt;26;i++) &#123; if(x-i&gt;=0) f[k][x]=(f[k][x]%mod+f[k-1][x-i]%mod)%mod; &#125; &#125; &#125; while(T--) &#123; scanf(&quot;%s&quot;,s+1); int tot=0; int len=strlen(s+1); for(int i=1;i&lt;=len;i++) tot+=(int)(s[i]-&#x27;a&#x27;); cout&lt;&lt;f[len][tot]%mod-1&lt;&lt;&#x27;
&#x27;;//要减去最开始的那一个！！ &#125; return 0;&#125; CF106C Buns 设f[k][r]f[k][r]f[k][r]表示只做前k种包子，使用了r克面团，获得的收益 实际上类似于一个背包 考虑某种包子做iii个，则有状态转移方程 ∀k,r,f[k][r]=max(f[k][r],f[k−1][r−i∗c[k]]+i∗d[k])  orall k,r ,f[k][r]=max(f[k][r],f[k-1][r-i*c[k]]+i*d[k]) ∀k,r,f[k][r]=max(f[k][r],f[k−1][r−i∗c[k]]+i∗d[k]) #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=1005;int n,m;int a[maxn],b[maxn],c[maxn],d[maxn];int c0,d0;int f[15][maxn];int ans;int main()&#123; cin&gt;&gt;n&gt;&gt;m&gt;&gt;c0&gt;&gt;d0; for(int i=1;i&lt;=m;i++) cin&gt;&gt;a[i]&gt;&gt;b[i]&gt;&gt;c[i]&gt;&gt;d[i]; //整挺好，就一个类似于背包的动态规划 for(int k=1;k&lt;=m;k++) for(int r=0;r&lt;=n;r++) for(int i=0;i*b[k]&lt;=a[k]&amp;&amp;i*c[k]&lt;=r;i++) f[k][r]=max(f[k][r],f[k-1][r-i*c[k]]+i*d[k]); for(int r=0; r&lt;=n; r++) ans=max(ans,f[m][r]+(n-r)/c0*d0); cout&lt;&lt;ans&lt;&lt;&#x27;
&#x27;; return 0;&#125;

【全程NOIP计划】图论算法 最短路算法 常用的最短路算法SPFA,Dijkstra,Floyd算法 最短路问题，就是对于有权图的两个点，找到一条连接两个点的路径，使得路径的权值和最小 在说最短路算法之前，必须了解松弛的概念 其实n简单，如果a→b+b→ca ightarrow b+b ightarrow ca→b+b→c的距离比a→ca ightarrow ca→c的小，那么就可以用前者代替a到c的距离 各种各样 最短路实际上就是不断做松弛操作 Floyd 可以求出图中任意两点的最短路，过程很简单 首先枚举松弛操作的中间点，再枚举松弛的左右两个点，然后做松弛操作 由于Floyd算法暴力枚举的特性，所以用邻接矩阵很方便 很显然，复杂度为O(n3)O(n^3)O(n3) for(int k=1;k&lt;=n;k++) for(int i=1;i&lt;=n;i++) for(int j=1;j&lt;=n;j++) a[i][j]=min(a[i][j],a[i][k]+a[k][j]); 正确性 怎么证明正确性？ 对于任意两个点之间的最短路，假设有m个节点那么m一定小于n，因为重复经过同样的点没有意义（除非有负环，但是如果有负环最短路就没有意义，因为可以通过刷负环来刷最短路） 那么这m个点在外层循环都会被枚举一次，接着内层的两重循环一定会枚举到这个点在最短路上相邻的两个点 这个点被松弛之后，我们就可以认为它已经不在最短路上了，因为此时的a→b→ca ightarrow b ightarrow ca→b→c和a→ca ightarrow ca→c是一样的 外层循环做完之后，两个点之间的所有m个点也都被消除完了，这两个点的距离就是最短路 易错点 有一个易错点，就是三个循环的顺序不要搞错了 先枚举中间，再枚举两边 因为，如果左边先枚举，那么n次循环之后，松弛的点对都是从左边出发的，如果没有恰好沿着路径的顺序去枚举中间的点，就无法松弛整条路径 有一个神奇的结论，只要Floyd整个过程连续做三遍，不管三个循环是什么顺序，跑出来的结果都是对的，但是不建议使用，主要是慢啊 作用 裸的最短路实际上用的不多，用到了也很简单，基本上是看做一个工具来用 Floyd实际上还可以处理除了最短路以外其他的问题 P2419 Cow Contest S 思路 拓扑排序可以，但是Floyd也可以 这样点很少，边很多的图就很适合使用Floyd 如果用e[i][j]e[i][j]e[i][j]表示能不能推出i&lt;j的关系，如果e[i][k]=1且e[k][j]=1e[i][k]=1且e[k][j]=1e[i][k]=1且e[k][j]=1，那么e[i][j]=1e[i][j]=1e[i][j]=1 这样我们就可以处理出任意两点间的大小关系，有或者没有 然后如果对于一个点，我们能确定剩下所有点和它的大小关系 那么这个点的排名就被确定了 如果一个点，对于其他任何一个点都能推出它的关系，然后它的排名就确定了 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;int n,m;int e[105][105];void floyd()&#123; for(int k=1;k&lt;=n;k++) for(int i=1;i&lt;=n;i++) for(int j=1;j&lt;=n;j++) e[i][j]|=(e[i][k]&amp;e[k][j]);//用floyd来解决直接的关系 &#125;int main()&#123; cin&gt;&gt;n&gt;&gt;m; int l,r; while(m--) &#123; cin&gt;&gt;l&gt;&gt;r; e[l][r]=1; &#125; floyd(); int cnt=0; for(int i=1;i&lt;=n;i++) &#123; int mark=1; for(int j=1;j&lt;=n;j++) if(j!=i&amp;&amp;e[j][i]==0&amp;&amp;e[i][j]==0)//如果有谁不能确定 &#123; mark=0; break; &#125; cnt+=mark; &#125; cout&lt;&lt;cnt&lt;&lt;endl; return 0;&#125; P2888 Cow Hurdles S 思路 让我想到了营救那道题目 实际上就是二分答案加判断 但是用Floyd处理dp关系可以更简单的做这个题目 e[i][j]e[i][j]e[i][j]表示从i到j经过的路径中，最小的最大栏杆高度 容易得到类似于Floyd的关系 也就是说如果走i→k→ji ightarrow k ightarrow ji→k→j的路线，那么栏杆的最大高度为max(e[i][k],e[k][j])max(e[i][k],e[k][j])max(e[i][k],e[k][j]) 如果这个最大值小于i→ji ightarrow ji→j之间的最大值，那么就可以更新这个最小的最大值 也就是先用O(n3)O(n^3)O(n3)来处理一个Floyd，然后再用O(t)O(t)O(t)处理答案 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int INF=0x3f3f3f3f;const int maxn=305;int n,m,T;int a[maxn][maxn];int main()&#123; memset(a,20,sizeof(a)); cin&gt;&gt;n&gt;&gt;m&gt;&gt;T; for(int i=1;i&lt;=m;i++) &#123; int s,e,h; cin&gt;&gt;s&gt;&gt;e&gt;&gt;h; a[s][e]=h; &#125; for(int k=1;k&lt;=n;k++) for(int i=1;i&lt;=n;i++) for(int j=1;j&lt;=n;j++) a[i][j]=min(a[i][j],max(a[i][k],a[k][j])); while(T--) &#123; int l,r; cin&gt;&gt;l&gt;&gt;r; if(a[l][r]!=336860180) cout&lt;&lt;a[l][r]&lt;&lt;&#x27;
&#x27;; else cout&lt;&lt;-1&lt;&lt;&#x27;
&#x27;; &#125; return 0;&#125; P2047 社交网络 思路 这道题目和前两道题目差不多，只不过除了求i到j的路径数量，还要求i经过k到j的路径数量 最短路径比较好求，如果e[i][k]和e[k][j]e[i][k]和e[k][j]e[i][k]和e[k][j]更新了e[i][j]e[i][j]e[i][j]的话，让cnt[i][j]=cnt[i][k]∗cnt[k][j]cnt[i][j]=cnt[i][k]*cnt[k][j]cnt[i][j]=cnt[i][k]∗cnt[k][j]就可以了 如果e[i][k]+e[k][j]=e[i][j]e[i][k]+e[k][j]=e[i][j]e[i][k]+e[k][j]=e[i][j]那么还要让cnt[i][j]+=cnt[i][k]∗cnt[k][j]cnt[i][j]+=cnt[i][k]*cnt[k][j]cnt[i][j]+=cnt[i][k]∗cnt[k][j] 因为数据量过小，所以这样来表示是可以的，主要运用的是乘法原理 题目个每个点求∑s!=v,t!=vc(s,t,v)c(s,t)\sum_{s!=v,t!=v}c(s,t,v)c(s,t)∑s!=v,t!=v​c(s,t,v)c(s,t) 那么就先跑Floyd，然后枚举每个点，再枚举s和t，用cnt[s][v]∗cnt[v][t]/cnt[s][t]cnt[s][v]*cnt[v][t]/cnt[s][t]cnt[s][v]∗cnt[v][t]/cnt[s][t]计算就可以了 void floyd()&#123; for(int k=1;k&lt;=n;k++) for(int i=1;i&lt;=n;i++) for(int j=1;j&lt;=n;j++) &#123; if(e[i][k]+e[k][j]&lt;e[i][j]) &#123; e[i][j]=e[i][k]+e[k][j]; cnt[i][j]=cnt[i][k]*cnt[k][j]; &#125; else if(e[i][j]+e[k][j]==e[i][j]) &#123; cnt[i][j]+=cnt[i][k]*cnt[k][j]; &#125; &#125;&#125;int main()&#123; for(int i=1;i&lt;=n;i++) &#123; for(int j=1;j&lt;=n;j++) e[i][j]=INF; e[i][i]=0; &#125; int l,r,v; while(m--&gt;0) &#123; cin&gt;&gt;l&gt;&gt;r&gt;&gt;v; e[l][r]=v; e[r][l]=v; cnt[l][r]=1; cnt[r][l]=1; &#125; floyd(); for(int k=1;k&lt;=n;k++) &#123; double ans=0; for(int i=1;i&lt;=n;i++) for(int j=1;j&lt;=n;j++) if(cnt[i][j]&amp;&amp;e[i][k]+e[k][j]==e[i][j]) ans+=(double)(cnt[i][k]*cnt[k][j]/cnt[i][j]); printf(&quot;%.3lf&quot;,ans); &#125;&#125; Bellman-Ford 这是一个单源最短路算法 也就是能求出从某个点出发到剩下所有点的最短路 这个算法用dis[v]dis[v]dis[v]表示从s到v的距离 算法总共进行n-1轮，每轮枚举所有的边u到v，来做s到u到u的松弛操作 不难理解，第一轮会求出和s间距一条边的最短路，第二轮会求出间距小于等于2条边的最短路，第n-1轮回求出间距小于等于n-1条边的最短路 由于最短路最多有n-1条边，所以n-1轮之后每个点都求到了真正的最短路 显然这个算法的复杂度是O(NM)O(NM)O(NM)的，n是点数，m是边数 显然这个算法适合直接结构体来存边，也就是边表 void bellman_ford()&#123; for(int i=1;i&lt;=n;i++) dis[i]=INF; dis[s]=0; for(int k=1;k&lt;n;k++) &#123; for(int i=1;i&lt;=ecnt;i++) if(dis[e[i].x]+e[i].v&lt;dis[e[i].y]) dis[e[i].y]=dis[e[i].x]+e[i].v; &#125;&#125; SPFA 上面的一个算法有一个优化，实际上就是spfa 我们每轮操作其实并不一定要把所有的边都松弛一遍 因为有一些店在上一轮之后最短路并没有发生变化，那么从这个点出发的边做松弛也一定没有变化 所以我们不再枚举n-1轮，而是用一个队列，表示刚刚发生过变化，准备要进行松弛的点 每次从队列里拿出一个点，然后枚举这个点的出边并进行松弛，如果出点的值边了，就把出点也加入队列 一个进一步的优化用flag[v]flag[v]flag[v]表示点v是否在队列里，如果已经在了，那显然是不用重复进队的 显然一开始就应该把s放进队列，然后从s开始松弛 也是用邻接链表来村边 void spfa()&#123; for(int i=1;i&lt;=n;i++) flag[i]=false; for(int i=1;i&lt;=n;i++) dis[i]=INF; dis[s]=0; q[++head]=s; for( ;tail&lt;=head; ++tail) &#123; flag[q[tail]]=0; for(int i=1) &#125;&#125; 复杂度 时间复杂度为O(VE)O(VE)O(VE)，有的时候并不比Bellman-Ford更快 作用 但是spfa并不是一无是处，当图中有负环的时候，Dijkstra这种纯粹求最短路的算法就挂了 因为负环实际上意味着图中没有最短路 而spfa有三种方式来判断是否存在负环: 1.用cnt[v]cnt[v]cnt[v]来表示从s到v的最短路经过了多少个点，如果u到v送出了s到v，那么就让cnt[v]cnt[v]cnt[v]更新为cnt[u]+1cnt[u]+1cnt[u]+1，之前提到过，一个正常的最短路不应该有超过n个点的，因此当cnt[v]&gt;ncnt[v]&gt;ncnt[v]&gt;n的时候有内鬼，终止交易 2.统计进队次数，一个点如果入队大于n次 3.dfs班也很简单，如果一个点被松弛了，就直接递归进这个点去松弛别人就可以了。如果一个点递归了一圈又回到自己了，显然有负环。一般第二种方法比第一种方法快一点，而第三种方法比前两种都要快。spfa判负环只能判有没有，不能找哪里，如果要找哪里，要用tarjan算法 P3199 最小圈 思路 问题实际上是求C=∑w[i]/kC=\sum w[i]/kC=∑w[i]/k，其中i是边，w[i]w[i]w[i]是边权，k是边数 问题显然存在二分单调性，也就是如果答案太大，那么不符合最小的要求，但是一定可以找出来一个圈，使得比值小于等于这个答案，如果答案太小，那么一定找不到一个圈，使得比值满足这个答案 那么就可以二分答案ans，如果不存在∑w[i]/k≤ans\sum w[i]/k \le ans∑w[i]/k≤ans，则答案小，否则答案大 把这个式子变一下，就得到∑w[i]−k∗ans=∑(w[i]−ans)≤0\sum w[i]-k*ans=\sum(w[i]-ans) \le 0∑w[i]−k∗ans=∑(w[i]−ans)≤0 需要注意，负圈不一定是要每条边都小于0，而是只要权值和小于0的就可以刷最短路 所以满足∑(w[i]−ans)≤0\sum(w[i]-ans)\le 0∑(w[i]−ans)≤0的圈实际上就是一个负圈，因为答案是浮点数，所以$&lt;0和 \le0 $的区别不大 那么枚举出答案ans后给每个边权都减去ans，然后spfa判负环就可以了 这个实际上是一个01分数规划的过程 复杂度上线为O(nmlogw)O(nmlogw)O(nmlogw)，比较危险 Dijkstra 只要出现单源最短路一定要卡spfa的今天，单源最短路的最佳解法就是Dijkstra 实际上如果用stl的优先队列来写，Dijkstra也不会比spfa复杂到哪里去 Dijkstra其实就是一个堆优化的spfa spfa每次是从已经准备要松弛别人的点中选出某一个，而Dijkstra则是直接使用优先队列贪心地从中选出dis最小的那个 至于这个贪心的全局最优的证明，可以使用归纳法严格证明 每条边至多被访问一次，所以每个点的松弛次数不会超过边数 所以Dijkstra的时间复杂度为O(MlogN)O(MlogN)O(MlogN) 另一种理解 Dijkstra的思路其实是每次从dis中挑出dis最短的那个，之前没有被挑过的点出来松弛 Dijkstra实际上有一个O(nm)O(nm)O(nm)的做法，就是直接用for循环去找这个最短的的点，这也是为什么会有堆优化的Dijkstra的这种说法 本质上是用堆来维护dis数组的，但是要注意 不能直接对dis建堆，然后随着松弛操作改堆里的数据 如果直接改堆的数据，会破坏堆的结构，导致堆不能完成它应有的功能 因此还要没松弛一次就把出点入堆，然后出堆的时候去更新dis void dijkstra()&#123; for(int i=1;i&lt;=n;i++) dis[i]=INF; dis[s]=0; size=0; push((nod)&#123;x,0&#125;); while(size) &#123; while(size&amp;&amp;heap[1].y&gt;dis[heap[1].x]) pop(); if(!size) break; x=heap[1].x; dis[x]=heap[1].y; pop(); for(int i=link[x];i;i=e[i].next) if(dis[x]+e[i].v&lt;dis[e[i].y]) &#123; dis[e[i].y]=dis[x]+e[i].v; push((node)&#123;e[i].y,dis[e[i].y]&#125;); &#125; &#125;&#125; P2837 Milk Pumping G 思路 这个题看上去有二分单调性，又涉及到分数，似乎是分数规划 实际上并没有这么复杂，因为n很小，流量的上线也很小 所以直接枚举路径的流量，流量确定之后最大化流量/花费，实际上就是最小化花费 于是就可以跑Dijkstra，要求流量大于等于枚举的流量的边才能参与松弛就行了 int dijkstra(int y)&#123; for(int i=1;i&lt;=n;i++) dis[i]=INF; dis[1]=0; size=0; push((nod)&#123;1,0&#125;); while(size) &#123; while(size&amp;&amp;heap[1].y&gt;dis[heap[1].x]) pop(); if(!size) break; x=heap[1].x; dis[x]=heap[1].y; pop(); for(int i=link[x];i;i=e[i].next) if(e[i].w&gt;=y&amp;&amp;dis[x]+e[i].v&lt;dis[e[i].y]) &#123; dis[e[i].y]=dis[x]+e[i].v; push((node)&#123;e[i].y,dis[e[i].y]&#125;); &#125; &#125; return dis[n];&#125;int main()&#123; …… dounble ans=0; for(int i=1;i&lt;=1000;i++) ans=max(ans,(double)i/dij(i)); printf(&quot;%lld
&quot;,(long long)(ans*1e6)); ……&#125; 最短路建模 差分约束 差分约束系统就是给你一堆变量，然后给你一堆形如ai−aj≤ca_i-a_j \le cai​−aj​≤c的不等式 像这样两个变量相减的形式就叫做差分，一堆变量相减就是差分系统 差分约束能告诉你差分系统中，任意两个变量最多是多少，或者是最少是多少 做法 如果有a1-a2&lt;=b,a2-a3&lt;=d,a1-a3&lt;=e 假设要求a1-a3的范围，我们发现除了a1-a3&lt;=e的条件之外，还有a1-a2+a2-a3=a1-a3&lt;=b+d 那么如果b+d&lt;=e,a1-a3就&lt;=b+d,否则a1-a3&lt;=e 发现了没，这个操作和最短路的松弛操作特别像 我们用e[i][j]e[i][j]e[i][j]来表示ai−aj≤e[i][j]a_i-a_j\le e[i][j]ai​−aj​≤e[i][j]，那么不难发现，对于一个中间点k，我们有e[i][j]=min(e[i]][j],e[i][k]+e[k][j])e[i][j]=min(e[i]][j],e[i][k]+e[k][j])e[i][j]=min(e[i]][j],e[i][k]+e[k][j])，于是我们就用一个最短路的模型表示一个差分约束系统，然后就可以用最短路算法解出想要的变量的差分关系 有的人就会问，如果同时出现左边右边符号颠倒的情况怎么办，一般就可以把符号和两个数的位置变化一下，一般不会出现变化不了的情况 还有一种题型就是判断有没有解，我们要考虑什么情况下无解，情况有很多，但是可以转化为一个情况，就是a-b&lt;=c且a-b&gt;=d而且c&lt;d,可以看成c-d&lt;0，这就意味着一条循环约束出现了负环，如果常规差分约束建完图之后有负环，那么就无解了 模板代码 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;queue&gt;#define int long long using namespace std;const int maxn=50005;struct edge&#123; int e,next,val;&#125;ed[maxn*2];int en,first[maxn];void add_edge(int s,int e,int val)&#123; en++; ed[en].next=first[s]; first[s]=en; ed[en].e=e; ed[en].val=val;&#125;int n,m;int d[maxn],num[maxn];bool vis[maxn];queue &lt;int&gt; q;bool spfa(int x)&#123; d[x]=0; q.push(x); vis[x]=true; num[x]++; while(q.size()) &#123; int x=q.front(); q.pop(); vis[x]=false; for(int i=first[x];i;i=ed[i].next) &#123; int e=ed[i].e,val=ed[i].val; if(d[e]&gt;d[x]+val) &#123; d[e]=d[x]+val; if(!vis[e]) &#123; q.push(e); vis[e]=true; num[e]++; if(num[e]==n+1) return false; &#125; &#125; &#125; &#125; return true; &#125;signed main()&#123; cin&gt;&gt;n&gt;&gt;m; for(int i=1;i&lt;=n;i++) d[i]=2147483647; for(int i=1;i&lt;=m;i++) &#123; int x,y,z; cin&gt;&gt;x&gt;&gt;y&gt;&gt;z; add_edge(y,x,z); &#125; for(int i=1;i&lt;=n;i++) add_edge(n+1,i,0); if(!spfa(n+1)) &#123; cout&lt;&lt;&quot;NO&quot;&lt;&lt;&#x27;
&#x27;; goto end; &#125; for(int i=1;i&lt;=n;i++) cout&lt;&lt;d[i]&lt;&lt;&quot; &quot;; end: ; return 0;&#125; P1993 小k的农场 思路 直接差分约束系统，判断是否有解就可以了 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;queue&gt;#define int long long using namespace std;const int maxn=50005;struct edge&#123; int e,next,val;&#125;ed[maxn*2];int en,first[maxn];void add_edge(int s,int e,int val)&#123; en++; ed[en].next=first[s]; first[s]=en; ed[en].e=e; ed[en].val=val;&#125;int n,m;int d[maxn],num[maxn];bool vis[maxn];queue &lt;int&gt; q;bool spfa(int x)&#123; d[x]=0; q.push(x); vis[x]=true; num[x]++; while(q.size()) &#123; int x=q.front(); q.pop(); vis[x]=false; for(int i=first[x];i;i=ed[i].next) &#123; int e=ed[i].e,val=ed[i].val; if(d[e]&gt;d[x]+val) &#123; d[e]=d[x]+val; if(!vis[e]) &#123; q.push(e); vis[e]=true; num[e]++; if(num[e]==n+1) return false; &#125; &#125; &#125; &#125; return true; &#125;signed main()&#123; cin&gt;&gt;n&gt;&gt;m; memset(d,0x3f,sizeof(d)); for(int i=1;i&lt;=m;i++) &#123; int op; cin&gt;&gt;op; if(op==1) &#123; int a,b,c; cin&gt;&gt;a&gt;&gt;b&gt;&gt;c; add_edge(a,b,-c); &#125; else if(op==2) &#123; int a,b,c; cin&gt;&gt;a&gt;&gt;b&gt;&gt;c; add_edge(b,a,c); &#125; else &#123; int a,b; cin&gt;&gt;a&gt;&gt;b; add_edge(a,b,0); add_edge(b,a,0); &#125; &#125; for(int i=1;i&lt;=n;i++) add_edge(n+1,i,0); if(!spfa(n+1)) &#123; cout&lt;&lt;&quot;No&quot;&lt;&lt;&#x27;
&#x27;; return 0; &#125; cout&lt;&lt;&quot;Yes&quot;&lt;&lt;&#x27;
&#x27;; return 0;&#125; P3275 糖果 思路 跟上一道题目一样差不多，处理一下差分约束系统 a不比b少就是a&gt;=b a比b少怎么办？ 实际上就是a&lt;b等价于a&lt;=b-1 于是a比b少表示为b-a&gt;=1 现在约束能建了，问题是要求总数最小 可以建立一个抽象节点，表示0颗糖的基准线 然后抽象点往所有点约束为1的边，表示每人至少分一颗糖 这里需要注意，由于求的是最小值，约束是a-b&gt;=c，因此这里求的是最长路，要找出最大的那个下限 最后所有人dis就是不得不满足的下限，然后就能得到答案了 传递闭包 传递闭包的数学概念比较抽象，不太好懂，但是做出来很简单 简单说就是，两个关系i–&gt;k和k–&gt;j可以复合出一个新关系i–&gt;j，这就是传递性 给你一个集合，集合里定义了一个关系i–&gt;j，再定义一个关系i–&gt;j，满足： 1.对于所有满足i–&gt;j,使得i能通过–&gt;的复合关系连接到j，但是不满足i–&gt;j 2.除此之外不存在i和j，使得i能通过–&gt;的复合关系链接到j，但是不满足i–&gt;j 精简版说法，就是传递闭包是关系的极大生成集，因为 1.如果a是b的祖先，那么a肯定是b的父母的父母的父母的…… 2.不存在如果a是b父母的父母的父母的……,我们就不能称a为b的祖先的情况 实际上还是有点难理解，但是直接看怎么做吧 对于一个邻接矩阵e，e[i][j]=0e[i][j]=0e[i][j]=0不满足关系i–&gt;j，e[i][j]=1e[i][j]=1e[i][j]=1表示满足关系i–&gt;j 然后我们对e做与操作的Floyd，也就是松弛操作为e[i][j]=e[i][k]and[k][j]e[i][j]=e[i][k] and[k][j]e[i][j]=e[i][k]and[k][j] 就这？对，我们之前实际上遇到了一个差不多的例题 强连通分量 强连通分量指的是图的一个极大的子图，满足图内任意两点内任意两点之间可以相互到达 需要注意的是，强连通分量的概念是针对有向图的，无向图没有强连通分量的说法，因为对于无向图，只要是一个连通图就能任意互相到达 强连通分量分成两个部分第一个是任意两个点可以相互到达，这个比较好理解 比如完全图，也就是任意两个点都连接两个方向的边 再比如一个有向环，也满足这个条件 而极大的子图就是说，再加入原图中的任意一个点以及这个点的边到这个子图内，都不能满足互相到达的条件 比如一个完全图子完全图，虽然能互相到达，但是不是极大的 Tarjan算法 求一个图的强连通分量一般用tarjan算法，这里的tarjan算法只指dfs树，也就是dfn-low的那一套理论 首先对于任意一个有向图，我们显然可以用dfs来遍历整个图，每个点只经过一次，并不用管所有点都经过没，那么按照dfs递归的关系，把遍历过程画出来，就是一个dfs树 tarjan在dfs树的基础上定义了dfn和low的概念 dfn就是dfs过程被访问到的顺序 而low表示的是这个点能到达的所有点中，dfn最小的点 tarjan算法首先用一个栈按顺序记录dfs遍历过的点，同时计算dfn和low，每当发现一个点的dfn等于low，那么就把这个点以及栈中之后的所有点弹出来，作为一个强连通分量 void tarjan(int x,int fa)&#123; vis[x]=true; dfn[x]=low[x]=++dfs_cnt; s[++top]=x; for(int i=link[x];i;i=e[i].next) &#123; if(!dfn[e[i].y]) &#123; tarjan(e[i].y,x); low[x]=min(low[x],low[e[i].y]); &#125; else if(vis[e[i].y]) low[x]=min(low[x],dfn[e[i].y]); &#125; if(dfn[x]==low[x]) &#123; grouP_cnt++; int temp; do&#123; temp=s[top--]; group[temp]=group_cnt; vis[temp]=false; &#125;while(temp!=x) &#125;&#125; 正确性 为什么 ？ 对于子图的一个点，如果这个点可以到达任意一个点，而任意一个点也可以到达这个点，我们就说这个子图是任意两点互相到达的 在tarjan算法中，这个点就是dfn等于low的点 我们注意到，在tarjan算法中，这个点就是dfn等于low的点 我们注意到，在tarjan算法中，只要dfn[x]=low[x]dfn[x]=low[x]dfn[x]=low[x]，那么x就会被弹出来，因此对于一个点x的子树中的点y，只有两种情况：要么已经被弹出来了，要么low[y]=low[x]low[y]=low[x]low[y]=low[x] 不可能low[y]&lt;low[x]low[y]&lt;low[x]low[y]&lt;low[x]，因为x可以到y，所以y能到的x也能到，那么应该low[x]≤low[y]low[x]\le low[y]low[x]≤low[y]才对 而如果low[y]&gt;low[x]low[y]&gt;low[x]low[y]&gt;low[x]，那么到回溯到low[y]low[y]low[y]对应的那个点的时候，y就被弹出栈了 所以栈里面留下来的也一定都能到达x 同时显然x也能到达它的子节点们 因此当dfn[x]=low[x]dfn[x]=low[x]dfn[x]=low[x]的时候，我们就说x的子树内任意互达 同时这些子树上的点往上最多只能到达x，到不了子树外面的点 因此把任意子树外的点加进来，都会破坏任意互达的条件 再来看为dfn[y]=low[y]dfn[y]=low[y]dfn[y]=low[y]而被提前弹出栈的的y的子树的点 这些碘同样往外最多只能到达y，到达不了x，因此把y子树中的点加进来也不能满足任意互达的条件 所以tarjan算法找到的点的集合，当然也包括这些点之间的边的集合，是强联通分量 P2341 最受欢迎的牛 思路 我们发现对于一个强联通分量内的牛的机会是相同的，要么一起当明星，要么都当不了明星 因为团体内的任意一头牛会爱慕别的牛，如果团体外的所有牛都爱它，那么就会传递到剩下的所有牛的身上 因此我们可以先做tarjan缩点，把一个强连通分量的牛看成一个整体来考虑 原来牛之间的边要转化为团体间的边 这是我们发现，缩点之后的图变成了一个DAG 前面我们提到过，环是强连通分量，因此如果图中还有环，显然还可以继续缩点 因此把所有强连通分量都缩完的图一定是一个DAG 如果整个DAG只有一个点的出度为n，那么显然所有的点都可以到达这个点 所以当我们缩完点之后发现DAG中只有一个点出度为0，那么我们说这个点中的所有的奶牛都可以当明星

