 &#123; fac[i]++; fac[x/i]++; &#125; if(i*i==x) fac[x/i]--; &#125; fac[x]++; return ;&#125;int main()&#123; n=read(); for(int i=1;i&lt;=n;i++) &#123; a[i]=read(); record(a[i]); &#125; sort(a+1,a+1+n); for(int i=2;i&lt;=a[n];i++) maxx=max(maxx,fac[i]); cout&lt;&lt;maxx&lt;&lt;endl; return 0;&#125; CF776B Sherlock and his girlfriend 思路 注意到这是二分图，一边是质数，一边是合数 运用埃氏筛把合数都筛掉 然后质数和合数的颜色不同就可以了 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;int n;bool p[100005];int main()&#123; cin&gt;&gt;n; p[0]=true,p[1]=true; for(int i=2;i*i&lt;=n+1;i++) &#123; if(!p[i]) &#123; for(int j=i*2;j&lt;=n+1;j+=i) p[j]=true; &#125; &#125; if(n&lt;3) cout&lt;&lt;1&lt;&lt;&#x27;
