&#x27;; return 0;&#125; P4139 上帝与集合的正确用法 思路 题目要求出的是2222… mod p2^{2^{2^{2…}}} \space mod \space p2222… mod p的值 根据扩展欧拉定理 ab≡{ab mod φ(p)+φ(p)(b&gt;φ(p))ab(b≤φ(p)) (mod p) a^b\equiv \left\{ egin{aligned}a^{b 	ext{ mod }φ(p)+φ(p)}(b&amp;&gt;φ(p))\a^b(b≤φ(p))\end{aligned}ight. 	ext{ (mod }p) ab≡{ab mod φ(p)+φ(p)(bab(b≤φ(p))​&gt;φ(p)) (mod p) 可以通过一个函数来递归求 可是题目中让求的是无限层，并不是有限层，怎么办啊？ 不要紧，在一层层的递归中，ppp一遍遍的被求其φφφ值，最终必定会降到111。原因很简单，因为：φ(p)&lt;p (p&gt;1)φ(p)&lt;p\space(p&gt;1)φ(p)&lt;p (p&gt;1) 而且降的很快，所以递归很快就会结束 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=1e7+5;int T,tot;int pri[1000005],phi[maxn];bool vis[maxn];inline int read()&#123; int x=0,f=1;char ch=getchar(); while (ch&lt;&#x27;0&#x27;||ch&gt;&#x27;9&#x27;)&#123;if (ch==&#x27;-&#x27;) f=-1;ch=getchar();&#125; while (ch&gt;=&#x27;0&#x27;&amp;&amp;ch&lt;=&#x27;9&#x27;)&#123;x=x*10+ch-48;ch=getchar();&#125; return x*f;&#125;int ksm(int a,int b,int p)&#123; int ans=1%p; for( ;b;b&gt;&gt;=1) &#123; if(b&amp;1) ans=(long long)ans*a%p; a=(long long)a*a%p; &#125; return ans;&#125;int dfs(int x)&#123; if(x==1) return 0; int n=phi[x]; return ksm(2,dfs(n)+n,x);&#125;void init()&#123; for(int i=2;i&lt;=maxn;i++) &#123; if(!vis[i]) pri[++tot]=i,phi[i]=i-1; for(int j=1;j&lt;=tot&amp;&amp;pri[j]*i&lt;=maxn;j++) &#123; vis[pri[j]*i]=1; if(i%pri[j]) phi[i*pri[j]]=phi[i]*phi[pri[j]]; else &#123; phi[i*pri[j]]=phi[i]*pri[j]; &#125; &#125; &#125;&#125;int main()&#123; init(); T=read(); while(T--) cout&lt;&lt;dfs(read())&lt;&lt;&#x27;
&#x27;; return 0;&#125; 一道例题 题目 求[1,107][1,10^7][1,107]内的所有素数，内存限制1MB 思路 吧[1,107][1,10^7][1,107]分成k段分别求解 对于区间[l,r][l,r][l,r]，枚举不大于r\sqrt{r}r​的所有素数p，在[l,r][l,r][l,r]中筛去p的倍数 需要预处理[1,n][1,\sqrt{n}][1,n​]的所有素数 时间复杂度kn+nloglognk\sqrt{n}+nlog^{log^n}kn​+nloglogn 空间复杂度n+n/k\sqrt{n}+n/kn​+n/k P2568 gcd 思路 线性筛出不大于NNN的所有素数ppp。问题就转化为求(x,y)=p(x,y)=p(x,y)=p的个数 设x=x′p,y=y′px=x&#x27;p,y=y&#x27;px=x′p,y=y′p那么有(x′,y′)=1(x&#x27;,y&#x27;)=1(x′,y′)=1且1≤x,y≤N/p1 \le x,y \le N/p1≤x,y≤N/p 转化为求(x,y)=1(x,y)=1(x,y)=1且1≤x,y≤n1 \le x,y \le n1≤x,y≤n的个数 答案为2∑i=1nϕ(i)−12\sum_{i=1}^n\phi(i)-12∑i=1n​ϕ(i)−1 线性筛筛出欧拉函数，预处理前缀和就可以了 然后对于每个小于等于NNN的素数处理累加到答案里就可以了 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#define int long longusing namespace std;const int maxn=1e7+5;int pri[maxn],phi[maxn],s[maxn];bool vis[maxn];int n,tot;long long ans=0;void init(int x)&#123; phi[1]=1; for(int i=2;i&lt;=x;i++) &#123; if(!vis[i]) pri[++tot]=i,phi[i]=i-1; for(int j=1;j&lt;=tot&amp;&amp;pri[j]*i&lt;=x;j++) &#123; vis[pri[j]*i]=1; if(i%pri[j]) phi[i*pri[j]]=phi[i]*phi[pri[j]]; else &#123; phi[i*pri[j]]=phi[i]*pri[j]; &#125; &#125; &#125; for(int i=1;i&lt;=x;i++) s[i]=s[i-1]+phi[i];&#125; signed main()&#123; cin&gt;&gt;n; init(n); for(int i=1;i&lt;=tot;i++) ans+=(2*s[n/pri[i]]-1); cout&lt;&lt;ans&lt;&lt;&#x27;
&#x27;; return 0;&#125; P2155 沙拉公主的困惑 思路 感谢@Siyuan PS:越来越意识到开long long的重要性 答案是： ∑i=1n![gcd(i,m!)=1] \sum_{i=1}^{n!}[gcd(i,m!)=1] ∑i=1n!​[gcd(i,m!)=1] 我们类比gcd 我们知道n≥mn \ge mn≥m，所以我们可以把[1,n!][1,n!][1,n!]分成若干段 准确地来说是 n!m!\dfrac {n!} {m!}m!n!​段，每段的答案是一样的，这是由gcd的更相减损术得到的 然后我们就可以更换求和的上界 n!m!∑i=1m![gcd(i,m!)=1] \dfrac {n!} {m!}\sum_{i=1}^{m!}[gcd(i,m!)=1] m!n!​∑i=1m!​[gcd(i,m!)=1] 右边的就是1到m！中与m互质的数，也就是 φ(m!) \varphi(m!) φ(m!) 我们知道,设n=∏pikin =\prod p_i^{k_i}n=∏piki​​,则φ(n)=n∏(1−1pi)=∏piki−1∗(pi−1)\varphi(n)=n \prod(1- rac 1 {p_i})=\prod p_i^{k_i-1}*(p_i-1)φ(n)=n∏(1−pi​1​)=∏piki​−1​∗(pi​−1) 所以我们设m!=∏i=1kpicim!=\prod_{i=1}^kp_i^{c_i}m!=∏i=1k​pici​​,可以得到： φ(m!)=m!∏i=1kpi−1pi \varphi(m!)=m! \prod_{i=1}^k \dfrac {p_i-1} {p_i} φ(m!)=m!∏i=1k​pi​pi​−1​ 所以讲这个东西带入上面的式子，答案就是 n!∏i=1kpi−1pi n!\prod_{i=1}^k \dfrac {p_i-1} {p_i} n!∏i=1k​pi​pi​−1​ 那个玩意儿我们可以用线性筛求 时间复杂度O(N+T)O(N+T)O(N+T) #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#define int long longusing namespace std;const int maxn=1e7+5;int T,R;int tot,pri[maxn],fac[maxn],inv[maxn];int ans[maxn];bool vis[maxn];void init()&#123; fac[0]=fac[1]=1; inv[0]=inv[1]=1; ans[0]=ans[1]=1; for(int i=2;i&lt;=maxn-5;i++) &#123; fac[i]=(long long)(fac[i-1]*i)%R;//算阶乘 inv[i]=(long long)((R-R/i)*inv[R%i])%R;//逆元 &#125; //欧拉筛 for(int i=2;i&lt;=maxn-5;i++) &#123; if(!vis[i]) pri[++tot]=i; for(int j=1;j&lt;=tot&amp;&amp;i*pri[j]&lt;=maxn-5;j++) &#123; vis[i*pri[j]]=1; if(i%pri[j]==0) break; &#125; &#125; for(int i=2;i&lt;=maxn-5;i++) &#123; ans[i]=ans[i-1]; if(!vis[i]) ans[i]=(long long)(ans[i]*(i-1)%R*inv[i]%R)%R; &#125;&#125;signed main()&#123; cin&gt;&gt;T&gt;&gt;R; init(); while(T--) &#123; int n,m; cin&gt;&gt;n&gt;&gt;m; cout&lt;&lt;(long long)fac[n]*ans[m]%R&lt;&lt;&#x27;
&#x27;; &#125; return 0;&#125; CF632D Longest Subsequence 思路 我们要选出尽可能多的数字，满足他们的最小公倍数不大于m 分析题意可以得到，如果一个数大于m的话那么它和其他数的最小公倍数一定大于m 所以先把大于m的数字筛掉 然后 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=1000005;int n,m;int a[maxn],ans[maxn];int cnt[maxn];bool vis[maxn];int main()&#123; std::ios::sync_with_stdio(false); cin&gt;&gt;n&gt;&gt;m; for(int i=1;i&lt;=n;i++) &#123; cin&gt;&gt;a[i]; if(a[i]&lt;=m) cnt[a[i]]++; &#125; for(int i=1;i&lt;=n;i++) &#123; if(a[i]&lt;=m&amp;&amp;!vis[a[i]]) &#123; vis[a[i]]=true; for(int j=1;j*a[i]&lt;=m;j++) ans[a[i]*j]+=cnt[a[i]]; &#125; &#125; int maxx=-9999999; int lcm=1; for(int i=1;i&lt;=m;i++) &#123; if(maxx&lt;ans[i]) &#123; maxx=ans[i]; lcm=i; &#125; &#125; cout&lt;&lt;lcm&lt;&lt;&quot; &quot;&lt;&lt;maxx&lt;&lt;&#x27;
&#x27;; for(int i=1;i&lt;=n;i++) &#123; if(lcm%a[i]==0) cout&lt;&lt;i&lt;&lt;&quot; &quot;; &#125; cout&lt;&lt;&#x27;
&#x27;; return 0;&#125; CF582A GCD Table 思路 为啥CF的题目就是这么妙呢？ 是我不配了 观察得到三个结论 1.G中最大的数也一定是a中最大的数，因为gcd(a,a)=agcd(a,a)=agcd(a,a)=a，如果它是最大的话，也一定是最大的 2.G中次大的数也一定是a中次大的数 3.第三第四大的数可能是由最大和次大的GCD产生的； 所以算法就有这样的步骤 1.令p为G中最大的数，在G中删掉p，在a中加入p 2.对于a中的所有其他数，设为q，在G中删除两个gcd(p,q)gcd(p,q)gcd(p,q) 3.若G为空则结束，否则回到1 则时间复杂度为O(n2logGi,j)O(n^2logG_{i,j})O(n2logGi,j​) 因为值域到10910^9109，所以要用map处理 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;map&gt;using namespace std;const int maxn=505;int n,cnt,tot;int arr[maxn],a[maxn*maxn];map &lt;int,int&gt; m;int gcd(int a,int b)&#123; return b? gcd(b,a%b):a;&#125;int main()&#123; cin&gt;&gt;n; for(int i=1;i&lt;=n*n;i++) &#123; int x; cin&gt;&gt;x; if(!m[x]) a[++cnt]=x; m[x]++; &#125; //从小到大排序，方便从大到小遍历 sort(a+1,a+1+cnt); for(int i=cnt;i&gt;=1&amp;&amp;tot&lt;n; ) &#123; //如果前面没有，就一直减 while(!m[a[i]]) i--; arr[++tot]=a[i]; m[a[i]]--; for(int j=1;j&lt;tot;j++) m[gcd(a[i],arr[j])]-=2; //它和其他数的gcd都删掉了，所以要减两遍 &#125; for(int i=1;i&lt;=tot;i++) cout&lt;&lt;arr[i]&lt;&lt;&quot; &quot;; return 0; &#125;

【全程NOIP计划】组合计数选讲 组合数基础 加法原理 加法原理，总共的等于各个相互独立的相加 乘法原理 两个不相干的事情同时发生，总共的情况是两种情况相乘 抽屉原理 容斥原理 排列数 从n个中选m个，考虑顺序 总的方案数为Pnm=n!(n−m)!P_n^m= rac {n!} {(n-m)!}Pnm​=(n−m)!n!​，或者可以记录为AnmA_n^mAnm​ P5520 青原樱 思路 实际上就是两个幼苗之间至少有一个空位，然后m个幼苗之间必须有m-1个空位 所以把这m-1个位置空出来，然后剩下的位置乱插 答案就是An−m+1mA_{n-m+1}^mAn−m+1m​ #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;int type,n,m,p;long long A(int n,int m)&#123; long long res=1%p; for(int i=n-m+1;i&lt;=n;i++) res=(res*i)%p; return res%p;&#125;int main()&#123; cin&gt;&gt;type&gt;&gt;n&gt;&gt;m&gt;&gt;p; cout&lt;&lt;A(n-m+1,m)&lt;&lt;&#x27;
&#x27;; return 0;&#125; 组合数 从n个选m个，不考虑顺序 总的方案数为Cnm=n!m!(n−m)!C_n^m= rac {n!}{m!(n-m)!}Cnm​=m!(n−m)!n!​，实际上选出的人再进行随便的排列组合，一共有m!m!m!种，所以也可以推出来排列数的公式，他们两个之间的关系是Cnm∗m!=PnmC_n^m*m!=P_n^mCnm​∗m!=Pnm​ 组合数常用的式子 Cnm=Cn−1m+Cn−1m−1 C_n^m=C_{n-1}^m+C_{n-1}^{m-1} Cnm​=Cn−1m​+Cn−1m−1​ 实际上这个就对应杨辉三角形 1 1 1 1 2 1 ……………… 我们可以知道一个二项式定理 (x+y)n=∑i=1nCni∗xiyn−i (x+y)^n=\sum_{i=1}^n C_n^i*x^iy^{n-i} (x+y)n=∑i=1n​Cni​∗xiyn−i 怎么证明？ 常见的组合问题 1.20个人去霓虹玩，站成一排拍纪念照，但是anan和他的女朋友必须贴贴，请问有多少种方案 先把他们两个看成一个人 就变成了19个人拍照，站成一排的方案数量为19!19!19!，再排他和他女朋友的方案为2 所以总的方案数量为19!×219! 	imes 219!×2 2.20个人去霓虹玩，站成一排拍纪念照，但是anan和他的女朋友吵架了不能贴贴，有多少种方案 实际上可以直接用容斥原理，用总的方案数减去问题1的方案数即可 但是怎么不用容斥原理呢？ 先不考虑他们两个人 我们先把剩下18个人排好，方案数量为18!18!18! 然后18个之间，包括最左和最右一共有19个空，再把他和他女朋友放进去，一共有P192P_{19}^2P192​的方案数量 所以总的方案数量就为18!×P19218! 	imes P_{19}^218!×P192​ 3.Zcysky大王有n个相同的纸片人老婆，他准备把这些老婆分给m个不同的手下，Zcysky秉持着雨露均沾的原则，每个人至少能分到一个纸片人老婆，一共有多少种方案 使用隔板法，实际上就是在n-1个空里面选m-1个空插，当然，隔板是一样的，所以不用考虑顺序，也就是最后总的方案数为Cn−1m−1C_{n-1}^{m-1}Cn−1m−1​ 4.Zcysky大王有n个相同的纸片人老婆，他准备把这些老婆分给m个不同的手下，但是他早就看某些人不爽了，所以有些人可能一个人都分不到，一共有多少种方案 还是隔板法，但是有可能两个隔板之间一个纸片人都没有。每个人再发一个老婆，所以一共有n+m-1个空，然后选m-1个插，所以总的方案数量为Cn+m−1m−1C_{n+m-1}^{m-1}Cn+m−1m−1​ Lucas定理 卡特兰数 h(n)=h(0)∗h(n−1)+h(1)∗h(n−2)+……+h(n−1)∗h(0)=∑h(i)∗h(n−i−1) h(n)=h(0)*h(n-1)+h(1)*h(n-2)+……+h(n-1)*h(0) \=\sum h(i)*h(n-i-1) h(n)=h(0)∗h(n−1)+h(1)∗h(n−2)+……+h(n−1)∗h(0)=∑h(i)∗h(n−i−1) 有什么作用呢？ n对括号匹配的数目 n个节点组成二叉树 n边形三角划分 n个点依次进出栈的出战顺序 n*n的矩阵从左下角到右上角不经过对角线 求卡特兰数有两种方式 h(n)=C2nn−C2nn+1h(n)=C2nnn+1 h(n)=C_{2n}^n-C_{2n}^{n+1} \h(n)= rac {C_{2n}^n}{n+1} h(n)=C2nn​−C2nn+1​h(n)=n+1C2nn​​ Monochromatic Triangles 题目 空间中有n个点，m条红边，任意3个点不共线 每两个点用红线或者蓝线相连，如果一个三角形的三边颜色相同，那么称为同色三角形 给你一组数据，计算同色三角形的总数 思路 根据容斥原理 同色三角形=三角形总数-不同色三角形数量 则三角形的总数量就为Cn3C_n^3Cn3​ 对于一个点，如果连出去d[i]d[i]d[i]条红边，就有n−d[i]−1n-d[i]-1n−d[i]−1条蓝边 根据乘法原理，它贡献的三角形数量就是d[i]∗(n−d[i]−1)d[i]*(n-d[i]-1)d[i]∗(n−d[i]−1) 由于一个异色三角形会被计算两遍 答案就是Cn3−∑d[i]∗(n−d[i]−1)2C_n^3-\sum  rac{d[i]*(n-d[i]-1)}2Cn3​−∑2d[i]∗(n−d[i]−1)​ P3166 数三角形 题目 给定一个n*m的网络，请计算三点都在格点上的三角形一共有多少个 注意三角形的三点不能共线 思路 任选三个点的方案数减去三点共线的方案数量 任选三个点方案数是Cn∗m3C_{n*m}^3Cn∗m3​ 三点共线的方案数：同一排，同一列，同一斜线 对于同一斜线的可以枚举两个端点，中间的用gcd计算 #include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;long long n,m;long long ans;long long gcd(long long a,long long b)&#123; return b? gcd(b,a%b):a;&#125;int main()&#123; cin&gt;&gt;n&gt;&gt;m; n++,m++; ans=(n*m)*(n*m-1)*(n*m-2)/6;//三个点选择的计算公式 if(n&gt;=3) ans-=(n*(n-1)*(n-2)*m/6); if(m&gt;=3) ans-=(m*(m-1)*(m-2)*n/6); for(int i=1;i&lt;n;i++) &#123; for(int j=1;j&lt;m;j++)//枚举斜线，向左斜一遍，向右斜一遍，拒绝早恋 ans-=(n-i)*(m-j)*(gcd(i,j)-1)*2; &#125; cout&lt;&lt;ans&lt;&lt;&#x27;
&#x27;; return 0;&#125; P4478 上学路线 题目 从n*m个网格图的左下角走到右上角 有t个坐标不能经过 只能向上或者向右走 问有多少种不同的走法，对p取模 思路 容斥原理Dp 先把终点当做障碍点，把所有的障碍点按x为第一关键词，y为第二关键字从小到大排序 设f[i]f[i]f[i]为到达第i个障碍点且不经过任何障碍点的方案数量 设G[i][j]G[i][j]G[i][j]表示到达从第i个障碍点到第j个障碍点的方案数量 从（x1,y1）走到(x2,y2)的方案数量为Cx2+y2−x1−y1x2−x1C_{x2+y2-x1-y1}^{x2-x1}Cx2+y2−x1−y1x2−x1​，这个用lucas定理求就可以了 f[i]=G[0][i]−∑G[j][i]∗f[j]f[i]=G[0][i]-\sum G[j][i]*f[j]f[i]=G[0][i]−∑G[j][i]∗f[j] 当p=1000003的时候直接求解 p=1019663265的时候先分解质因数，然后使用CRT合并 矩阵相关 矩阵的定义 有m∗nm*nm∗n个数aij排成m行n列的数表称为m行n列的矩阵，简称m∗nm*nm∗n矩阵 $ A= egin{bmatrix} a_{11} &amp; a_{12} &amp;\dots &amp;a_{1n}\ a_{21} &amp; a_{22} &amp;\dots &amp;a_{2n}\a_{31} &amp; a_{32} &amp;\dots &amp;a_{3n}\dots &amp; \dots &amp; &amp;\dots\a_{m1} &amp; a_{m2} &amp;\dots &amp;a_{mn}\ \end{bmatrix} $ 这m×nm 	imes nm×n个数组被称为矩阵A的元素 行数与列数都等于n的矩阵称为n阶矩阵或者n阶方阵 矩阵的加减法 加法：C=A+BC=A+BC=A+B，则Ci,j=Ai,j+Bi,jC_{i,j}=A_{i,j}+B_{i,j}Ci,j​=Ai,j​+Bi,j​ $  egin{bmatrix}1 &amp; 4 &amp; 2 \ 2 &amp; 0 &amp; 0 \end{bmatrix} +  egin{bmatrix}0 &amp; 0 &amp; 5 \ 7 &amp; 5 &amp; 0 \end{bmatrix}  egin{bmatrix} 1+0 &amp; 4+0 &amp; 2+5 \ 2+7 &amp; 0+5 &amp; 0+0 \end{bmatrix}  egin{bmatrix} 1 &amp; 4 &amp; 7 \ 9 &amp; 5 &amp; 0 \end{bmatrix} 减法: 减法:减法:C=A-B,则,则,则C_{i,j}=A_{i,j}-B_{i,j}
