//位运算版本#include &lt;iostream&gt;using namespace std;int power(int a,int b,int p)&#123;	int ans=1%p;	for( ;b;b&gt;&gt;=1)	&#123;		if(b&amp;1)		ans=(long long)ans*a%p;		a=(long long)a*a%p; 	&#125;	return ans;&#125;int main()&#123;	&#125; //递归版本#include &lt;iostream&gt;#include &lt;cstdio&gt;using namespace std;long long t,b,p,k,s,result=1;int pow(int a,int b,int p)&#123;	if(b==0)	return 1;	if(b==1)	return a%p;	t=pow(a,b/2,p);	if(b&gt;=2&amp;&amp;b%2==0)	return t*t%p;	if(b&gt;=2&amp;&amp;b%2==1)	return t*t*a%p;&#125;int main()&#123;&#125; 
