#include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=200005;struct node&#123;	int x,y,z,id;&#125;a[maxn];int c[maxn*4],k,n,b[maxn],qyj[maxn],f[maxn];int lowbit(int x)&#123;	return x&amp;(-x);&#125;void add(int x,int y)&#123;	for( ;x&lt;=k;x+=lowbit(x))	c[x]+=y;&#125;int ask(int x)&#123;	int res=0;	for( ;x;x-=lowbit(x))	res+=c[x];	return res;&#125;bool cmp1(const node &amp;a,const node &amp;b)&#123;	if(a.x!=b.x)	return a.x&lt;b.x;	if(a.y!=b.y)	return a.y&lt;b.y;	return a.z&lt;b.z;&#125;bool cmp2(const node &amp;a,const node &amp;b)&#123;	if(a.y!=b.y)	return a.y&lt;b.y;	if(a.z!=b.z)	return a.z&lt;b.z;	return a.x&lt;b.x;&#125;void cdq(int l,int r)&#123;	if(l==r)	return ;	int mid=(l+r)&gt;&gt;1;	int flag;	cdq(l,mid),cdq(mid+1,r);	sort(a+l,a+r+1,cmp2);	for(int i=l;i&lt;=r;i++)	(a[i].x&lt;=mid)?add(a[i].z,1),flag=i:b[a[i].id]+=ask(a[i].z);	for(int i=l;i&lt;=r;i++)	if(a[i].x&lt;=mid)	add(a[i].z,-1);&#125;int main()&#123;	cin&gt;&gt;n&gt;&gt;k;	for(int i=1;i&lt;=n;i++)	cin&gt;&gt;a[i].x&gt;&gt;a[i].y&gt;&gt;a[i].z,a[i].id=i;	sort(a+1,a+1+n,cmp1);	for(int i=1;i&lt;=n; )	&#123;		int j=i+1;		while(j&lt;=n&amp;&amp;a[j].x==a[i].x&amp;&amp;a[j].y==a[i].y&amp;&amp;a[j].z==a[i].z)		j++;		while(i&lt;j)		qyj[a[i].id]=a[j-1].id,i++;	&#125;	for(int i=1;i&lt;=n;i++)	a[i].x=i;	cdq(1,n);	for(int i=1;i&lt;=n;i++)	f[b[qyj[a[i].id]]]++;	for(int i=0;i&lt;n;i++)	cout&lt;&lt;f[i]&lt;&lt;&#x27;\n&#x27;;	return 0;&#125;
