#include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;int n,k;int a[1000005],q[1000005];int main()&#123;	cin&gt;&gt;n&gt;&gt;k;	for(int i=0;i&lt;n;i++)	cin&gt;&gt;a[i];	int hh=0,tt=-1;	for(int i=0;i&lt;n;i++)	&#123;		if(hh&lt;=tt&amp;&amp;q[hh]&lt;i-k+1)		hh++;		while(hh&lt;=tt&amp;&amp;a[q[tt]]&gt;=a[i])		tt--;		q[++tt]=i;		if(i&gt;=k-1)		cout&lt;&lt;a[q[hh]]&lt;&lt;&quot; &quot;;	&#125;	cout&lt;&lt;endl;	hh=0,tt=-1;	for(int i=0;i&lt;n;i++)	&#123;		if(hh&lt;=tt&amp;&amp;q[hh]&lt;i-k+1)		hh++;		while(hh&lt;=tt&amp;&amp;a[q[tt]]&lt;=a[i])		tt--;		q[++tt]=i;		if(i&gt;=k-1)		cout&lt;&lt;a[q[hh]]&lt;&lt;&quot; &quot;;	&#125;	cout&lt;&lt;endl;	return 0;&#125;
