#include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;using namespace std;const int maxn=100010;int a[maxn+5];struct tree&#123;	int l,r;	long long dat,lazy;&#125;t[maxn*4+5];void pushup(int k)&#123;	t[k].dat=t[k&lt;&lt;1].dat+t[k&lt;&lt;1|1].dat;&#125;void build(int k,int l,int r)&#123;	t[k].l=l,t[k].r=r;	if(l==r)	&#123;		t[k].dat=a[l];		return ;	&#125;	int mid=(l+r)&gt;&gt;1;	build(k&lt;&lt;1,l,mid);	build(k&lt;&lt;1|1,mid+1,r);	pushup(k);&#125;void pushdown(int k)&#123;	if(t[k].lazy)	&#123;		t[k&lt;&lt;1].dat+=t[k].lazy*(t[k&lt;&lt;1].r-t[k&lt;&lt;1].l+1);		t[k&lt;&lt;1|1].dat+=t[k].lazy*(t[k&lt;&lt;1|1].r-t[k&lt;&lt;1|1].l+1);		t[k&lt;&lt;1].lazy+=t[k].lazy;		t[k&lt;&lt;1|1].lazy+=t[k].lazy;		t[k].lazy=0;	&#125;&#125;void updata(int k,int l,int r,int v)&#123;	if(l&lt;=t[k].l&amp;&amp;r&gt;=t[k].r)	&#123;		t[k].dat+=(long long)v*(t[k].r-t[k].l+1);		t[k].lazy+=v;		return ;	&#125;	pushdown(k);	int mid=(t[k].l+t[k].r)&gt;&gt;1;	if(l&lt;=mid)	updata(k&lt;&lt;1,l,r,v);	if(r&gt;mid)	updata(k&lt;&lt;1|1,l,r,v);	pushup(k);&#125;long long query(int k,int l,int r)&#123;	if(l&lt;=t[k].l&amp;&amp;r&gt;=t[k].r)	return t[k].dat;	pushdown(k);	int mid=(t[k].l+t[k].r)&gt;&gt;1;	long long ans=0;	if(l&lt;=mid)	ans+=query(k&lt;&lt;1,l,r);	if(r&gt;mid)	ans+=query(k&lt;&lt;1|1,l,r);	return ans;&#125;int main()&#123;	std::ios::sync_with_stdio(false);	int n,m;	cin&gt;&gt;n&gt;&gt;m;	for(int i=1;i&lt;=n;i++)	cin&gt;&gt;a[i];	build(1,1,n);	for(int i=1;i&lt;=m;i++)	&#123;		int o;		cin&gt;&gt;o;		if(o==1)		&#123;			int x,y,k;			cin&gt;&gt;x&gt;&gt;y&gt;&gt;k;			updata(1,x,y,k);			continue;		&#125;		else		&#123;			int x,y;			cin&gt;&gt;x&gt;&gt;y;			cout&lt;&lt;query(1,x,y)&lt;&lt;&#x27;\n&#x27;;		&#125;	&#125;	return 0;&#125;
