#include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;string&gt;#include &lt;cstring&gt;using namespace std;const int maxn=1e6+5;int n;long long x1,y1,x2,y2;long long x[maxn*2];struct scanline&#123;	long long l,r,h;	int mark;	bool operator &lt; (const scanline &amp;rhs) const	&#123;		return h&lt;rhs.h;	&#125;&#125;line[maxn*2];struct tree&#123;	int l,r;	int sum;	long long len;&#125;t[maxn*4];void pushup(int k)&#123;	if(t[k].sum)	t[k].len=x[t[k].r+1]-x[t[k].l];	else	t[k].len=t[k&lt;&lt;1].len+t[k&lt;&lt;1|1].len;&#125;void build(int k,int l,int r)&#123;	t[k].l=l,t[k].r=r;	t[k].len=0;	t[k].sum=0;	if(l==r)	return ;	int mid=(l+r)&gt;&gt;1;	build(k&lt;&lt;1,l,mid);	build(k&lt;&lt;1|1,mid+1,r);&#125;void edit_tree(int k,long long l,long long r,int c)&#123;	if(x[t[k].r+1]&lt;=l||r&lt;=x[t[k].l])	return ;	if(l&lt;=x[t[k].l]&amp;&amp;x[t[k].r+1]&lt;=r)	&#123;		t[k].sum+=c;		pushup(k);		return ;	&#125;	edit_tree(k&lt;&lt;1,l,r,c);	edit_tree(k&lt;&lt;1|1,l,r,c);	pushup(k);&#125;int main()&#123;	cin&gt;&gt;n;	for(int i=1;i&lt;=n;i++)	&#123;		cin&gt;&gt;x1&gt;&gt;y1&gt;&gt;x2&gt;&gt;y2;		x[2*i-1]=x1,x[2*i]=x2;		line[2*i-1]=(scanline)&#123;x1,x2,y1,1&#125;;		line[2*i]=(scanline)&#123;x1,x2,y2,-1&#125;;	&#125;	n&lt;&lt;=1;	sort(line+1,line+1+n);	sort(x+1,x+1+n);	//离散化 	int tot=unique(x+1,x+1+n)-x-1;	build(1,1,tot-1);	long long ans=0;	for(int i=1;i&lt;n;i++)	&#123;		edit_tree(1,line[i].l,line[i].r,line[i].mark);				ans+=t[1].len*(line[i+1].h-line[i].h);	&#125;	cout&lt;&lt;ans&lt;&lt;endl;	return 0;&#125;
可持久化线段树求第k小的数(主席树)
#include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#define int long longusing namespace std;const int maxn=200005;const int INF=1e9;struct tree&#123;	int ls,rs;	int sum;&#125;t[maxn*20];int n,m;int c,tot;int a[maxn],b[maxn],root[maxn];int build(int l,int r)//建树 &#123;	int p=++tot;//新增一个节点 	t[p].sum=0;	if(l==r)	return p;	int mid=(l+r)&gt;&gt;1;	t[p].ls=build(l,mid);	t[p].rs=build(mid+1,r);	return p; &#125;int insert(int now,int l,int r,int x,int delta)&#123;	int p=++tot;//新开一个节点 	t[p]=t[now];	if(l==r)	&#123;		t[p].sum+=delta;//在副本上进行加减，保留了历史版本 		return p;	&#125;	int mid=(l+r)&gt;&gt;1;	if(x&lt;=mid)	t[p].ls=insert(t[now].ls,l,mid,x,delta);	else	t[p].rs=insert(t[now].rs,mid+1,r,x,delta);	t[p].sum=t[t[p].ls].sum+t[t[p].rs].sum;	return p;&#125;int ask(int p,int q,int l,int r,int k)//表示在p，q两个节点上，值域为[l,r],求第k小的数 &#123;	if(l==r)	return l;//左端点等于右端点，找到了答案 	int mid=(l+r)&gt;&gt;1;	int lcnt=t[t[p].ls].sum-t[t[q].ls].sum;	if(k&lt;=lcnt)	return ask(t[p].ls,t[q].ls,l,mid,k);	else	return ask(t[p].rs,t[q].rs,mid+1,r,k-lcnt);&#125;signed main()&#123;	cin&gt;&gt;n&gt;&gt;m;	for(int i=1;i&lt;=n;i++)	&#123;		cin&gt;&gt;a[i];		b[++c]=a[i];	&#125;	sort(b+1,b+c+1);//离散化 	c=unique(b+1,b+c+1)-(b+1);	root[0]=build(1,c);	for(int i=1;i&lt;=n;i++)	&#123;		int x=lower_bound(b+1,b+c+1,a[i])-b;//离散化continuing		root[i]=insert(root[i-1],1,c,x,1);	&#125;	for(int i=1;i&lt;=m;i++)	&#123;		int l,r,k;		cin&gt;&gt;l&gt;&gt;r&gt;&gt;k;		int ans=ask(root[r],root[l-1],1,c,k);		cout&lt;&lt;b[ans]&lt;&lt;&#x27;\n&#x27;;	&#125;	return 0;&#125;
