//dijkstra 常用#include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;queue&gt;using namespace std;const int maxn=100010,maxm=1000010;struct edge&#123;	int e,next,val;&#125;ed[maxm];int en,first[maxn]; int n,m,s;int d[maxn];bool v[maxn];priority_queue &lt;pair&lt;int,int&gt; &gt; q;void add_edge(int s,int e,int w)&#123;	en++;	ed[en].next=first[s];	first[s]=en;	ed[en].e=e;	ed[en].val=w;&#125;void dijkstra()&#123;	for(int i=1;i&lt;=n;i++)	d[i]=2147483647;	memset(v,0,sizeof(v));	d[s]=0;	q.push(make_pair(0,s));	while(q.size())	&#123;		int x=q.top().second;		q.pop();		if(v[x]) continue;		v[x]=1;		for(int i=first[x];i;i=ed[i].next)		&#123;			int y=ed[i].e,z=ed[i].val;			if(d[y]&gt;d[x]+z)			&#123;				d[y]=d[x]+z;				q.push(make_pair(-d[y],y));  			&#125;		&#125;	&#125;&#125;int main()&#123;	cin&gt;&gt;n&gt;&gt;m&gt;&gt;s;	for(int i=1;i&lt;=m;i++)	&#123;		int x,y,z;		cin&gt;&gt;x&gt;&gt;y&gt;&gt;z;		add_edge(x,y,z);	&#125;	dijkstra();	for(int i=1;i&lt;=n;i++)	cout&lt;&lt;d[i]&lt;&lt;&quot; &quot;;	cout&lt;&lt;endl;	return 0; &#125;
