//spfa 慎用#include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;queue&gt;#define re register#define ll long longusing namespace std;const int maxn=100010,maxm=1000010;struct edge&#123;	int e,next,val;&#125;ed[maxm];int en,first[maxn],d[maxn];void add_edge(int s,int e,int w)&#123;	en++;	ed[en].next=first[s];	first[s]=en;	ed[en].e=e;	ed[en].val=w;&#125;bool v[maxn];int n,m,s;queue &lt;int&gt; q;void spfa()&#123;	for(re int i=1;i&lt;=n;i++)		d[i]=2147483647;	memset(v,0,sizeof(v));	d[s]=0,v[s]=1;	q.push(s);	while(q.size())	&#123;		int x=q.front();		q.pop();		for(re int i=first[x];i;i=ed[i].next)		&#123;			int y=ed[i].e,z=ed[i].val;			if(d[y]&gt;d[x]+z)			&#123;				d[y]=d[x]+z;				if(!v[y]) q.push(y);			&#125;		&#125;	&#125;&#125;int main()&#123;	cin&gt;&gt;n&gt;&gt;m&gt;&gt;s;	for(re int i=1;i&lt;=m;i++)	&#123;		int x,y,z;		cin&gt;&gt;x&gt;&gt;y&gt;&gt;z;		add_edge(x,y,z); 	&#125;	spfa();	for(re int i=1;i&lt;=n;i++)	printf(&quot;%d &quot;,d[i]);	return 0;&#125;
