#include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#include &lt;queue&gt;using namespace std;const int maxn=30005;int n,m;struct edge&#123;	int e,next,val;&#125;ed[maxn*2];int en,first[maxn];void add_edge(int s,int e,int val)&#123;	en++;	ed[en].next=first[s];	first[s]=en;	ed[en].e=e;	ed[en].val=val;&#125;void reset()&#123;	for(int i=0;i&lt;maxn*2;i++)	ed[i].next=ed[i].e=ed[i].val=0;	for(int i=0;i&lt;maxn;i++)	first[i]=0;&#125;int d[maxn],cnt[maxn];bool vis[maxn];queue &lt;int&gt; q;bool spfa()&#123;	memset(d,0x3f,sizeof(d));	memset(vis,false,sizeof(vis));	memset(cnt,0,sizeof(cnt));	d[1]=0,vis[1]=true;	q.push(1);	while(q.size())	&#123;		int x=q.front();		q.pop();		vis[x]=false;		for(int i=first[x];i;i=ed[i].next)		&#123;			int e=ed[i].e,val=ed[i].val;			if(d[e]&gt;d[x]+val)			&#123;				d[e]=d[x]+val;				cnt[e]=cnt[x]+1;				if(cnt[e]&gt;=n) return true;				if(!vis[e])				&#123;					q.push(e);					vis[e]=true; 				 &#125;			&#125;		&#125;	&#125;	return false;&#125;int T; int main()&#123;	cin&gt;&gt;T;	while(T--)	&#123;		cin&gt;&gt;n&gt;&gt;m;		reset();		for(int i=1;i&lt;=m;i++)		&#123;			int x,y,z;			cin&gt;&gt;x&gt;&gt;y&gt;&gt;z;			add_edge(x,y,z);			if(z&gt;=0)			add_edge(y,x,z);		&#125;		if(spfa())		cout&lt;&lt;&quot;YES&quot;&lt;&lt;&#x27;\n&#x27;;		else 		cout&lt;&lt;&quot;NO&quot;&lt;&lt;&#x27;\n&#x27;; 	&#125;	return 0;&#125;
