//Kruskal#include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;cstring&gt;#include &lt;string&gt;#define re register#define ll long longusing namespace std;struct rec&#123;int x,y,z;&#125;edge[500010];int fa[100010],n,m,ans;bool operator &lt;(rec a,rec b)&#123;	return a.z&lt;b.z;&#125;int get(int x)&#123;	return fa[x]=(x==fa[x])? x:get(fa[x]);&#125;int main()&#123;	cin&gt;&gt;n&gt;&gt;m;	for(re int i=1;i&lt;=m;i++)		cin&gt;&gt;edge[i].x&gt;&gt;edge[i].y&gt;&gt;edge[i].z;	sort(edge+1,edge+m+1);	for(re int i=1;i&lt;=n;i++) fa[i]=i;	for(re int i=1;i&lt;=m;i++)	&#123;		int x=get(edge[i].x);		int y=get(edge[i].y);		if(x==y) continue;		fa[x]=y;		ans+=edge[i].z;	&#125;	cout&lt;&lt;ans&lt;&lt;endl;	return 0;&#125;
