//Prim #include &lt;iostream&gt;#include &lt;algorithm&gt;#include &lt;cstdio&gt;#include &lt;cstring&gt;#include &lt;string&gt;#define re register#define ll long longusing namespace std;int a[5005][5005],n,m,ans,d[5005];bool v[5005];void prim()&#123;	memset(d,0x3f,sizeof(d));	memset(v,0,sizeof(v));	d[1]=0;	for(re int i=1;i&lt;=n;i++)	&#123;		int x=0;		for(re int j=1;j&lt;=n;j++)		if(!v[j]&amp;&amp;(x==0||d[x]&gt;d[j])) x=j;		v[x]=1;		for(re int y=1;y&lt;=n;y++)		if(!v[y]) d[y]=min(d[y],a[x][y]);	&#125;&#125;int main()&#123;	cin&gt;&gt;n&gt;&gt;m;	memset(a,0x3f,sizeof(a));	for(int i=1;i&lt;=m;i++)	&#123;		int x,y,z;		cin&gt;&gt;x&gt;&gt;y&gt;&gt;z;		a[y][x]=a[x][y]=min(a[x][y],z);	&#125;	prim();	for(int i=2;i&lt;=n;i++) ans+=d[i];	cout&lt;&lt;ans&lt;&lt;endl;	return 0;&#125;
最近公共祖先Lca（倍增）
注意要设置
fa[s][0]=0,dep[s]=1
