#include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;algorithm&gt;#include &lt;string&gt;#include &lt;cstring&gt;using namespace std;const int maxn=100005;int t,dfn[maxn],low[maxn];int tot,belong[maxn],sum[maxn],f[maxn];int s[maxn],top;int n,m,val[maxn],x[maxn*2],y[maxn*2],ans;bool instack[maxn];struct edge&#123;	int e,next;&#125;ed[maxn*2];int en,first[maxn];void add_edge(int s,int e)&#123;	en++;	ed[en].next=first[s];	first[s]=en;	ed[en].e=e;&#125;void tarjan(int x)&#123;	s[++top]=x;	instack[x]=true;	t++;	dfn[x]=low[x]=t;	for(int i=first[x];i;i=ed[i].next)	&#123;		int e=ed[i].e;		if(!dfn[e])		&#123;			tarjan(e);			low[x]=min(low[x],low[e]);		&#125;		else if(instack[e])		&#123;			low[x]=min(low[x],dfn[e]);		&#125;	&#125;	if(dfn[x]==low[x])	&#123;		tot++;		while(s[top+1]!=x)		&#123;			belong[s[top]]=tot;			sum[tot]+=val[s[top]];			instack[s[top--]]=false;		&#125;	&#125;&#125;void search(int x)&#123;	if(f[x])	return ;	f[x]=sum[x];	int maxsum=0;	for(int i=first[x];i;i=ed[i].next)	&#123;		int e=ed[i].e;		if(!f[e])		search(e);		maxsum=max(maxsum,f[e]);	&#125;	f[x]+=maxsum;&#125;int main()&#123;	cin&gt;&gt;n&gt;&gt;m;	for(int i=1;i&lt;=n;i++)	cin&gt;&gt;val[i];	for(int i=1;i&lt;=m;i++)	&#123;		cin&gt;&gt;x[i]&gt;&gt;y[i];		add_edge(x[i],y[i]);	&#125;	for(int i=1;i&lt;=n;i++)	if(!dfn[i])	tarjan(i);	memset(ed,0,sizeof(ed));	memset(first,0,sizeof(first));	en=0;	for(int i=1;i&lt;=m;i++)	&#123;		if(belong[x[i]]!=belong[y[i]])		add_edge(belong[x[i]],belong[y[i]]);	&#125;	for(int i=1;i&lt;=tot;i++)	&#123;		if(!f[i])		&#123;			search(i);			ans=max(ans,f[i]);		&#125;	&#125;	cout&lt;&lt;ans&lt;&lt;endl;	return 0;&#125;
